const initialApps=[{company:'mercari',status:'ES作成中',deadline:'2026-07-18',next:'志望動機を仕上げる',priority:'高'},{company:'recruit',status:'一次面接',deadline:'2026-07-24',next:'過去質問を確認',priority:'中'},{company:'layerx',status:'応募予定',deadline:'2026-08-02',next:'社員訪問を探す',priority:'中'}];
const safeJSON=(key,fallback)=>{try{const v=JSON.parse(localStorage.getItem(key));return v??fallback}catch{return fallback}};
const defaultProfile={registered:false,updatedAt:null,liberal:'文系',grade:'大学3年',industries:['IT・Web'],jobTypes:['事業企画'],locations:['東京'],transfer:'どちらでも',salary:350,overtime:30,sizePreference:'どちらでも',stability:60,growth:80,autonomy:75,global:35,remote:60,strengths:'課題を見つけて、周囲を巻き込みながら改善できる',skills:'企画、データ分析、英語',studyAbroad:'なし',activities:'アルバイトで業務フロー改善、学園祭チーム運営'};
const storedSaved=safeJSON('codra_saved_companies',null);
const storedProfile=safeJSON('codra_profile',{});
const storedAppsRaw=safeJSON('codra_apps',null);
const storedApps=Array.isArray(storedAppsRaw)?storedAppsRaw:initialApps;
const app=document.querySelector('#app');const company=id=>companies.find(c=>c.id===id);const num=(v,d=0)=>Number.isFinite(Number(v))?Number(v):d;const clamp=v=>Math.max(0,Math.min(100,Math.round(num(v))));
const state={view:'dashboard',companyId:null,tab:'overview',filter:'すべて',query:'',profile:{...defaultProfile,...(storedProfile&&typeof storedProfile==='object'&&!Array.isArray(storedProfile)?storedProfile:{})},saved:new Set(Array.isArray(storedSaved)?storedSaved.filter(id=>company(id)):['mercari','recruit','layerx']),apps:Array.isArray(storedApps)?storedApps.filter(a=>a&&company(a.company)) : initialApps,esDocs:[],interviewAnswers:{},interviewAiFeedback:{},researchNotes:{},usingDemoSaved:!Array.isArray(storedSaved),usingDemoApps:!Array.isArray(storedAppsRaw),doneTasks:new Set(),compareIds:[]};
function logo(c){return `<span class="company-logo" style="background:${c.color}">${c.initial}</span>`}function toast(m){const t=document.querySelector('#toast');t.textContent=m;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),2200)}function persist(){try{localStorage.setItem('codra_profile',JSON.stringify(state.profile));localStorage.setItem('codra_saved_companies',JSON.stringify([...state.saved]));localStorage.setItem('codra_apps',JSON.stringify(state.apps))}catch{toast('保存できませんでした')}}
function overlap(a,b){return a.some(x=>b.some(y=>String(y).toLowerCase().includes(String(x).toLowerCase())||String(x).toLowerCase().includes(String(y).toLowerCase())))}
function scores(c){const p=state.profile,industry=overlap(p.industries||[],c.industries)?100:55,job=overlap(p.jobTypes||[],c.jobTypes)?100:58,work=[(p.locations||[]).some(x=>c.locations.includes(x))?100:55,p.transfer==='不可'?(c.transfer==='なし'?100:35):p.transfer==='可'?85:70,100-Math.abs(num(p.remote,50)-(c.remote.includes('フル')?90:c.remote.includes('併用')?65:25))].reduce((a,b)=>a+b,0)/3,skill=overlap(String(p.skills||'').split(/[、, ]+/).filter(Boolean),c.requiredSkills)?92:64,offer=clamp((100-Math.max(0,c.difficulty-55)*.8)*.7+skill*.15+industry*.15);const w={i:1.5,j:1.35,w:1.15,s:1.1,g:1+num(p.growth,50)/250,t:1+num(p.stability,50)/300,a:1+num(p.autonomy,50)/300,gl:1+num(p.global,50)/300};const total=clamp((industry*w.i+job*w.j+work*w.w+skill*w.s+c.growthScore*w.g+c.stabilityScore*w.t+c.autonomyScore*w.a+c.globalScore*w.gl)/Object.values(w).reduce((a,b)=>a+b,0));return{industry:clamp(industry),job:clamp(job),work:clamp(work),skill:clamp(skill),growth:c.growthScore,stability:c.stabilityScore,autonomy:c.autonomyScore,global:c.globalScore,offer,total}}
const classify=s=>s>=80?'本命企業':s>=60?'現実的に狙える企業':'挑戦企業';
function recommendation(c,s){const p=state.profile,m=[];if(p.global>=65&&c.globalScore>=75)m.push('海外案件への関心とグローバルな仕事環境');if(p.autonomy>=65&&c.autonomyScore>=75)m.push('若手から裁量を持って挑戦したい価値観');if(p.growth>=65&&c.growthScore>=80)m.push('成長性を重視する志向');if(p.stability>=65&&c.stabilityScore>=80)m.push('安定した事業基盤を求める条件');if(p.remote>=65&&c.remote.includes('リモート'))m.push('リモートワークを取り入れたい希望');if(!m.length)m.push(`${p.jobTypes?.[0]||'希望職種'}と${p.industries?.[0]||'希望業界'}への関心`);const caut=[];if(c.overtime>num(p.overtime,30))caut.push(`残業時間（${c.overtime}時間）が許容範囲を上回る可能性`);if(p.transfer==='不可'&&c.transfer!=='なし')caut.push('転勤の可能性があるため募集要項を確認');if(c.difficulty>=80)caut.push('選考難易度が高めのため早めの対策');const next=[];if(s.skill<80)next.push(`不足しやすいスキル（${c.requiredSkills.slice(0,2).join('・')}）の具体例を作る`);if(s.offer<70)next.push('企業理解と面接回答を深める');if(!next.length)next.push('経験をSTAR形式で整理して企業との接点を言語化する');return{main:`${m.slice(0,2).join('、')}を活かしやすく、現時点の適合度は${s.total}点です。`,matches:m,cautions:caut.length?caut:['大きな条件上の注意点はありません。公式情報で最終確認しましょう。'],next}}
function ranked(){return companies.map(c=>{const s=scores(c);return{...c,scores:s,classification:classify(s.total),rec:recommendation(c,s)}}).sort((a,b)=>b.scores.total-a.scores.total)}
function layout(html){app.innerHTML=html;document.querySelectorAll('.nav-item').forEach(b=>b.classList.toggle('active',b.dataset.view===state.view));bind()}
function card(c){const s=c.scores||scores(c),r=c.rec||recommendation(c,s);return `<article class="card company-card"><div class="company-top"><div class="company-brand">${logo(c)}<div><div class="company-name">${c.name}</div><div class="company-meta">${c.category} · ${c.companySize}</div></div></div><div class="card-actions"><label class="compare-check"><input type="checkbox" data-compare="${c.id}" ${state.compareIds.includes(c.id)?'checked':''}/> 比較</label><button class="save-btn ${state.saved.has(c.id)?'saved':''}" data-save="${c.id}" aria-label="${state.saved.has(c.id)?'保存を解除':'企業を保存'}">${state.saved.has(c.id)?'♥':'♡'}</button></div></div><div class="score-row"><div><div class="score">${s.total}<small> / 100</small></div><div class="company-meta">総合適合度</div></div><span class="tag ${s.total>=80?'tag-green':s.total>=60?'tag-blue':'tag-amber'}">${c.classification||classify(s.total)}</span></div><div class="score-bar"><i style="width:${s.total}%"></i></div><p class="reason">${r.main}</p><div class="recommend-details"><strong>共通点</strong><span>${r.matches.join(' / ')}</span><strong>注意点</strong><span>${r.cautions.join(' / ')}</span><strong>伸ばす要素</strong><span>${r.next.join(' / ')}</span></div><button class="link-btn detail-link" data-company="${c.id}">推薦理由と企業情報を見る →</button></article>`}
function completion(){const p=state.profile;return clamp(['liberal','grade','industries','jobTypes','locations','strengths','skills','activities'].reduce((x,k)=>x+(Array.isArray(p[k])?p[k].length?1:0:p[k]?1:0),0)/8*100)}function axis(){const p=state.profile,a=[];if(p.growth>=65)a.push('成長性');if(p.stability>=65)a.push('安定性');if(p.autonomy>=65)a.push('若手裁量');if(p.global>=65)a.push('海外案件');return a.length?`「${a.slice(0,3).join('」×「')}」を重視するキャリア設計`:'自分に合う働き方を探索中'}
function dashboard(){const list=ranked(),pc=completion();layout(`<section class="hero"><div><div class="eyebrow">Your career strategy</div><h1>こんにちは、ゆうきさん。</h1><p>今日も、自分らしいキャリアを一歩ずつ設計しましょう。</p></div><div class="hero-side"><div><div class="stat-label">プロフィール完成度</div><div class="stat-value">${pc}<small>%</small></div></div><div class="progress-ring" style="background:conic-gradient(var(--green) ${pc}%,#e8edf3 0)"><span>${pc}%</span></div></div></section><div class="grid grid-4"><div class="card stat-card"><div class="stat-label">就活進捗率</div><div class="stat-value">38<small>%</small></div><div class="stat-foot">↑ 先週より 8%</div></div><div class="card stat-card"><div class="stat-label">保存した企業</div><div class="stat-value">${state.saved.size}<small> 社</small></div><div class="stat-foot">あなたの条件で分析済み</div></div><div class="card stat-card"><div class="stat-label">選考中の企業</div><div class="stat-value">${state.apps.length}<small> 社</small></div><div class="stat-foot">次のアクションがあります</div></div><div class="card stat-card"><div class="stat-label">ES・面接対策</div><div class="stat-value">46<small>%</small></div><div class="stat-foot">回答をブラッシュアップ</div></div></div><div class="grid grid-2"><div><div class="section-head"><div><h2>今日やるべきこと</h2><p>締切・志望度・準備状況から優先度を算出</p></div><button class="link-btn" data-view="saved">すべて見る</button></div><div class="card">${state.apps.map((a,i)=>{const c=company(a.company);return c?`<div class="task ${state.doneTasks.has(i)?'done':''}"><button class="task-check" data-task="${i}">${state.doneTasks.has(i)?'✓':''}</button><div><div class="task-title">${a.next}</div><div class="task-sub">${c.name} · 締切 ${a.deadline.slice(5).replace('-','/')}</div></div><span class="task-priority">優先度 ${a.priority}</span></div>`:''}).join('')}</div></div><div><div class="section-head"><div><h2>締切が近い企業</h2><p>忘れないうちに次の一手を</p></div><button class="link-btn" data-view="saved">選考管理</button></div><div class="card">${state.apps.map(a=>{const c=company(a.company);return c?`<div class="deadline"><div><div class="deadline-title">${c.name}</div><div class="deadline-company">${a.status}</div></div><div class="date ${a.priority==='高'?'':'normal'}">${a.deadline.slice(5).replace('-','/')}<small> 締切</small></div></div>`:''}).join('')}</div></div></div><div class="section-head"><div><h2>あなた向けおすすめ企業</h2><p>プロフィールと重視度から再計算した現時点の仮説</p></div><div class="section-actions"><button class="secondary-btn" id="recalculate">↻ 再計算する</button><button class="link-btn" data-view="discover">企業を探す →</button></div></div><div class="grid grid-3">${list.slice(0,3).map(card).join('')}</div><div class="section-head"><div><h2>現在の就活軸</h2><p>${state.profile.updatedAt?`前回プロフィール更新：${new Date(state.profile.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'プロフィールを更新すると推薦精度が上がります'}</p></div><button class="link-btn" data-view="profile">分析を見る →</button></div><div class="card profile-card"><div class="profile-score">${Math.round((num(state.profile.growth)+num(state.profile.stability)+num(state.profile.autonomy))/3)}<small>/100</small></div><div><strong>${axis()}</strong><p class="company-meta">入力した経験・価値観から導いた、現時点の仮説です。</p><div class="chip-list">${(state.profile.jobTypes||[]).map(x=>`<span class="chip">${x}</span>`).join('')}${(state.profile.industries||[]).map(x=>`<span class="chip">${x}</span>`).join('')}</div></div></div>`)}
function discover(){const list=ranked().filter(c=>(state.filter==='すべて'||c.category.includes(state.filter)||c.companySize.includes(state.filter))&&c.name.toLowerCase().includes(state.query.toLowerCase()));layout(`<div class="eyebrow">Discover your fit</div><h1 class="page-title">企業を探す</h1><p class="page-desc">知名度だけでは見つからない、あなたに合う選択肢を見つけましょう。</p><div class="searchbar"><input class="input" id="company-search" value="${state.query}" placeholder="企業名・キーワードで検索"/><button class="primary-btn" id="search-btn">検索する</button></div><div class="filter-row">${['すべて','IT・Web','人材・メディア','広告代理店','金融','メーカー・IT','ベンチャー企業','大手企業'].map(f=>`<button class="filter-pill ${state.filter===f?'active':''}" data-filter="${f}">${f}</button>`).join('')}</div><div class="section-head"><div><h2>${list.length}社の企業</h2><p>サンプル情報 · 2026年7月15日時点 · 正式情報は企業公式サイトで確認してください</p></div><button class="secondary-btn" id="compare-btn">比較リスト（${state.compareIds.length}/3）</button></div><div class="grid grid-3">${list.length?list.map(card).join(''):`<div class="card empty"><strong>条件に一致する企業がありません</strong>検索条件を少しゆるめてみましょう。</div>`}</div>`)}
function compare(){const list=state.compareIds.map(company).filter(Boolean);if(!list.length){layout(`<div class="eyebrow">Compare your options</div><h1 class="page-title">企業比較</h1><div class="card empty"><strong>比較する企業を選択してください</strong>企業を探す画面で「比較」にチェックを入れると、最大3社まで比較できます。</div><button class="primary-btn" data-view="discover">企業を探す</button>`);return}const rows=[['総合適合度',c=>c.scores.total,'点'],['初任給',c=>c.salary,'万円〜'],['成長性',c=>c.growthScore,''],['安定性',c=>c.stabilityScore,''],['若手裁量',c=>c.autonomyScore,''],['海外案件',c=>c.globalScore,''],['残業時間',c=>c.overtime,'時間'],['転勤',c=>c.transfer,''],['リモートワーク',c=>c.remote,''],['選考難易度',c=>c.difficulty,''],['身につくスキル',c=>c.requiredSkills.join(' / '),'']];list.forEach(c=>c.scores=scores(c));layout(`<button class="back" data-view="discover">← 企業を探すへ戻る</button><div class="eyebrow">Compare your options</div><h1 class="page-title">企業比較</h1><p class="page-desc">あなたの重視度に合わせて、適合する数値を強調しています。</p><div class="card table-card"><table class="compare-table compare-enhanced"><thead><tr><th>比較項目</th>${list.map(c=>`<th>${logo(c)} <span>${c.name}</span></th>`).join('')}</tr></thead><tbody>${rows.map(([label,fn,unit])=>{const vals=list.map(fn),numeric=vals.every(v=>typeof v==='number'),best=numeric?Math.max(...vals):null;return `<tr><td>${label}</td>${vals.map(v=>`<td class="${numeric&&v===best?'best':''}"><b>${v}</b>${unit}</td>`).join('')}</tr>`}).join('')}</tbody></table></div><div class="notice">サンプル情報 · 基準日：2026年7月15日 · 正式な情報は必ず各社公式サイトで確認してください。</div>`)}
function saved(){layout(`<div class="eyebrow">Your applications</div><h1 class="page-title">保存企業・選考管理</h1><p class="page-desc">次にやることを明確にして、選考を前に進めましょう。</p><div class="card table-card"><div class="application-row" style="background:#fbfcff;color:var(--muted);font-size:10px;font-weight:700"><div>企業</div><div>選考状況</div><div>次の締切</div><div>優先度</div><div></div></div>${state.apps.length?state.apps.map((a,i)=>{const c=company(a.company);return c?`<div class="application-row"><div class="app-company">${c.name}<small>${c.category}</small></div><select class="status-select" data-status="${i}">${['気になる','応募予定','ES作成中','ES提出済み','Webテスト','一次面接','二次面接','最終面接','内定','不合格','辞退'].map(s=>`<option ${s===a.status?'selected':''}>${s}</option>`).join('')}</select><div><span class="date ${a.priority==='高'?'':'normal'}">${a.deadline}</span><small style="display:block;color:var(--muted);margin-top:3px">${a.next}</small></div><span class="tag ${a.priority==='高'?'tag-amber':'tag-blue'}">${a.priority}</span><button class="link-btn detail-link" data-company="${a.company}">詳細</button></div>`:''}).join(''):`<div class="empty"><strong>まだ選考を登録していません</strong>企業を保存すると、ここで選考を管理できます。</div>`}</div><div class="section-head"><div><h2>保存した企業</h2><p>比較したい企業を最大3社まで選べます</p></div><button class="link-btn" data-view="discover">企業を追加 →</button></div><div class="grid grid-3">${[...state.saved].map(id=>company(id)).filter(Boolean).map(c=>{const s=scores(c);return card({...c,scores:s,classification:classify(s.total),rec:recommendation(c,s)})}).join('')}</div>`)}
function documents(){layout(`<div class="eyebrow">Your preparation</div><h1 class="page-title">ES・面接対策</h1><p class="page-desc">あなたの経験を、伝わる言葉に変えていきます。</p><div class="grid grid-2"><div class="card"><div class="section-head" style="margin:0 0 10px"><div><h3>ESドキュメント</h3><p>編集可能な下書きです</p></div><button class="primary-btn" id="new-doc">＋ 新しく作る</button></div><div class="doc-item"><div><div class="doc-kind">志望動機 · Mercari</div><div class="doc-title">ユーザー起点で価値をつくる理由</div><div class="doc-meta">最終編集 2時間前 · 428文字</div></div><span class="tag tag-green">下書き</span></div><div class="doc-item"><div><div class="doc-kind">自己PR</div><div class="doc-title">チームの改善を進めた経験</div><div class="doc-meta">最終編集 3日前 · 386文字</div></div><span class="tag tag-blue">編集中</span></div></div><div class="card"><div class="section-head" style="margin:0 0 10px"><div><h3>面接対策</h3><p>回答の質を高めましょう</p></div><span class="score">46<small>%</small></span></div>${['なぜこの業界を志望していますか？','チームで困難を乗り越えた経験は？','入社後に実現したいことは？'].map((q,i)=>`<div class="doc-item"><div><div class="doc-title">${q}</div><div class="doc-meta">回答${i?'未作成':'済み'} · ${i?'練習しましょう':'フィードバックあり'}</div></div><button class="link-btn" data-interview="${i}">${i?'回答する':'見直す'} →</button></div>`).join('')}</div></div><div class="section-head"><div><h2>AIフィードバック</h2><p>断定ではなく、改善のための仮説として提案します</p></div></div><div class="card"><div class="metric-list">${[['結論の明確さ',82],['具体性',67],['企業との接続',74],['深掘りへの耐性',55]].map(([x,v])=>`<div class="metric"><span>${x}</span><div class="score-bar"><i style="width:${v}%"></i></div><b>${v}</b></div>`).join('')}</div></div>`)}
function profile(){const p=state.profile;layout(`<div class="eyebrow">Profile intelligence</div><h1 class="page-title">プロフィール分析</h1><p class="page-desc">入力した情報から見えた、現時点でのキャリア仮説です。</p><div class="section-actions profile-actions"><button class="primary-btn" id="edit-profile">プロフィールを編集</button><button class="secondary-btn" id="profile-reset">入力をリセット</button></div><div class="notice">これはAIによる断定ではなく、あなたの入力情報から導いた「現時点での仮説」です。経験を追加すると分析が変わることがあります。</div><div class="grid grid-2"><div class="card"><div class="analysis-block"><h3>あなたの就活軸</h3><p>${axis()}。${p.strengths||'経験と価値観'}を活かしながら、納得できる環境を探しています。</p></div><div class="analysis-block"><h3>強み</h3><p>${p.strengths||'プロフィールに強みを追加すると表示されます。'}</p></div><div class="analysis-block"><h3>適性のある働き方</h3><p>${p.remote>=65?'リモートワークを取り入れ、集中と対話を組み合わせる働き方。':'対面での協働を軸に、必要に応じてリモートを組み合わせる働き方。'}</p></div></div><div class="card"><div class="analysis-block"><h3>向いている業界</h3><div class="chip-list">${(p.industries||[]).map(x=>`<span class="chip">${x}</span>`).join('')||'<span class="chip">入力してください</span>'}</div></div><div class="analysis-block"><h3>向いている職種</h3><div class="chip-list">${(p.jobTypes||[]).map(x=>`<span class="chip">${x}</span>`).join('')||'<span class="chip">入力してください</span>'}</div></div><div class="analysis-block"><h3>将来伸ばすべきスキル</h3><ul class="bullet-list"><li>経験を具体的な数字で説明する力</li><li>企業の事業と自分の経験を接続する力</li><li>${p.skills||'希望職種に必要なスキル'}の深掘り</li></ul></div></div></div><div class="section-head"><div><h2>プロフィール完成度</h2><p>${p.updatedAt?`前回更新：${new Date(p.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'プロフィールを更新すると推薦精度が上がります'}</p></div></div><div class="card"><div class="metric-list">${[['基本情報',p.liberal&&p.grade?100:0],['希望条件',p.industries?.length&&p.jobTypes?.length?90:40],['経験・強み',p.strengths&&p.activities?90:35],['価値観',num(p.growth)+num(p.stability)>0?80:0]].map(([x,v])=>`<div class="metric"><span>${x}</span><div class="score-bar"><i style="width:${v}%;background:var(--green)"></i></div><b>${v}%</b></div>`).join('')}</div></div>`)}
function detail(){const c=company(state.companyId);if(!c){state.view='discover';return render()}const s=scores(c),r=recommendation(c,s);const body=state.tab==='why'?`<div class="card"><h3>なぜおすすめなのか</h3><p class="reason">${r.main}</p><h3>あなたとの共通点</h3><ul class="bullet-list">${r.matches.map(x=>`<li>${x}</li>`).join('')}</ul><h3>注意すべき点</h3><ul class="bullet-list">${r.cautions.map(x=>`<li>${x}</li>`).join('')}</ul><h3>内定に向けて伸ばす要素</h3><ul class="bullet-list">${r.next.map(x=>`<li>${x}</li>`).join('')}</ul></div>`:state.tab==='selection'?`<div class="grid grid-2"><div class="card"><h3>選考フロー</h3><div class="chip-list"><span class="chip">ES</span><span class="chip">Webテスト</span><span class="chip">一次面接</span><span class="chip">最終面接</span></div><h3 style="margin-top:25px">面接形式</h3><p class="reason">オンライン / 対面の併用。過去の質問は「なぜこの事業か」など。</p></div><div class="card"><h3>情報の信頼度</h3><p class="reason">公式情報・複数の体験談で確認</p><h3>更新日</h3><p class="reason">2026年7月10日</p></div></div>`:state.tab==='work'?`<div class="card"><h3>働き方・キャリア</h3><div class="table-card"><table class="compare-table"><tbody>${[['勤務地',c.locations.join(' / ')],['身につくスキル',c.requiredSkills.join(' / ')],['3年後のキャリア','プロジェクトリード / 専門性の確立'],['5年後のキャリア','事業責任者 / 新規事業への挑戦']].map(x=>`<tr><td>${x[0]}</td><td>${x[1]}</td></tr>`).join('')}</tbody></table></div></div>`:`<div class="grid grid-2"><div class="card"><h3>事業概要</h3><p class="reason">${c.detail}</p><div class="chip-list"><span class="chip">${c.locations.join(' / ')}</span><span class="chip">初任給 ${c.salary}万円〜</span></div></div><div class="card"><h3>あなたとの適合度</h3><div class="metric-list" style="margin-top:18px">${[['業界適合度',s.industry],['職種適合度',s.job],['働き方適合度',s.work],['スキル適合度',s.skill]].map(([x,v])=>`<div class="metric"><span>${x}</span><div class="score-bar"><i style="width:${v}%"></i></div><b>${v}</b></div>`).join('')}</div></div></div>`;layout(`<button class="back" data-view="discover">← 企業を探すへ戻る</button><div class="detail-head">${logo(c)}<div><h1>${c.name}</h1><div class="company-meta">${c.category} · サンプル企業情報</div></div><button class="primary-btn" data-save="${c.id}">${state.saved.has(c.id)?'保存済み':'企業を保存'}</button></div><div class="notice">サンプル情報 · 基準日：2026年7月15日 · 正式な情報は必ず企業公式サイトで確認してください。</div><div class="tabs">${[['overview','概要'],['why','おすすめ理由'],['work','事業・職種 / 働き方'],['selection','選考情報'],['selection','面接対策']].map(([t,x])=>`<button class="tab ${state.tab===t?'active':''}" data-tab="${t}">${x}</button>`).join('')}</div>${body}`)}
function selectField(n,l,v,o){return `<label class="form-label">${l}<select class="select" name="${n}">${o.map(x=>`<option ${v===x?'selected':''}>${x}</option>`).join('')}</select></label>`}function numberField(n,l,v){return `<label class="form-label">${l}<input class="input" type="number" name="${n}" value="${num(v)}" min="0" max="1000"/></label>`}function rangeField(n,l,v){return `<label class="form-label">${l}<div class="range-line"><input type="range" name="${n}" value="${clamp(v)}" min="0" max="100"/><output>${clamp(v)}</output></div></label>`}
function fields(p,step){const multi=(n,l,o)=>`<label class="form-label">${l}<div class="choice-grid">${o.map(x=>`<label class="choice"><input type="checkbox" name="${n}" value="${x}" ${(p[n]||[]).includes(x)?'checked':''}/><span>${x}</span></label>`).join('')}</div></label>`;if(step===1)return `<div class="form-grid">${selectField('liberal','文系・理系',p.liberal,['文系','理系','その他'])}${selectField('grade','学年',p.grade,['大学1年','大学2年','大学3年','大学4年','大学院1年','大学院2年'])}</div>${multi('industries','希望業界',['IT・Web','人材','広告','金融','メーカー','コンサルティング'])}${multi('jobTypes','希望職種',['事業企画','プロダクト企画','法人営業','マーケティング','エンジニア'])}`;if(step===2)return `<div class="form-grid">${multi('locations','希望勤務地',['東京','大阪','名古屋','福岡','全国','海外'])}${selectField('transfer','転勤の可否',p.transfer,['可','不可','どちらでも'])}${numberField('salary','希望年収（万円）',p.salary)}${numberField('overtime','残業時間の許容範囲（時間/月）',p.overtime)}</div>`;return `<div class="form-grid">${selectField('sizePreference','企業規模の志向',p.sizePreference,['大企業','ベンチャー','どちらでも'])}${rangeField('stability','安定性の重視度',p.stability)}${rangeField('growth','成長性の重視度',p.growth)}${rangeField('autonomy','若手裁量の重視度',p.autonomy)}${rangeField('global','海外案件の重視度',p.global)}${rangeField('remote','リモートワークの重視度',p.remote)}</div><label class="form-label">自分の強み<textarea class="textarea" name="strengths" rows="3">${p.strengths||''}</textarea></label><label class="form-label">保有スキル<textarea class="textarea" name="skills" rows="2">${p.skills||''}</textarea></label><label class="form-label">留学経験<textarea class="textarea" name="studyAbroad" rows="2">${p.studyAbroad||''}</textarea></label><label class="form-label">アルバイト・課外活動<textarea class="textarea" name="activities" rows="3">${p.activities||''}</textarea></label>`}
function readForm(form){const fd=new FormData(form),out={};for(const[k,v]of fd.entries()){if(['industries','jobTypes','locations'].includes(k))out[k]=[...(out[k]||[]),v];else if(['salary','overtime','stability','growth','autonomy','global','remote'].includes(k))out[k]=num(v);else out[k]=v}return out}
function profileModal(onboarding=false,step=1){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<div class="modal" role="dialog" aria-modal="true"><button class="modal-close" id="modal-close" aria-label="閉じる">×</button><div class="eyebrow">${onboarding?'Welcome to Codra':'Edit your profile'}</div><h2>${onboarding?'あなたに合う企業を見つける準備':'プロフィールを編集'}</h2><p class="modal-desc">Step ${step} / 3 · 入力はいつでも変更できます</p><div class="step-progress"><i style="width:${step/3*100}%"></i></div><form id="profile-form">${fields(state.profile,step)}<div class="modal-actions"><button type="button" class="secondary-btn" id="modal-skip">スキップ</button><div>${step>1?'<button type="button" class="secondary-btn" id="modal-back">戻る</button>':''}<button type="submit" class="primary-btn">${step<3?'次へ':'あなたに合う企業を探す'}</button></div></div></form></div>`;document.body.appendChild(modal);const form=modal.querySelector('form');modal.querySelector('#modal-close').onclick=()=>modal.remove();modal.onclick=e=>{if(e.target===modal)modal.remove()};modal.querySelectorAll('input[type=range]').forEach(x=>x.oninput=()=>x.nextElementSibling.value=x.value);modal.querySelector('#modal-skip').onclick=()=>{modal.remove();if(onboarding&&step<3)profileModal(true,step+1)};modal.querySelector('#modal-back')?.addEventListener('click',()=>{state.profile={...state.profile,...readForm(form)};modal.remove();profileModal(onboarding,step-1)});form.onsubmit=e=>{e.preventDefault();state.profile={...state.profile,...readForm(form)};if(step<3){modal.remove();profileModal(onboarding,step+1)}else{state.profile.registered=true;state.profile.updatedAt=new Date().toISOString();persist();modal.remove();toast('プロフィールを保存しました。推薦を更新しました');render()}}}
function bind(){document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{state.view=b.dataset.view;state.companyId=null;render()});document.querySelectorAll('[data-save]').forEach(b=>b.onclick=()=>{const id=b.dataset.save;state.saved.has(id)?state.saved.delete(id):state.saved.add(id);persist();toast(state.saved.has(id)?'企業を保存しました':'保存を解除しました');render()});document.querySelectorAll('.detail-link').forEach(b=>b.onclick=()=>{state.companyId=b.dataset.company;state.view='detail';state.tab='overview';render()});document.querySelectorAll('[data-filter]').forEach(b=>b.onclick=()=>{state.filter=b.dataset.filter;render()});document.querySelector('#search-btn')?.addEventListener('click',()=>{state.query=document.querySelector('#company-search').value;render()});document.querySelector('#company-search')?.addEventListener('keydown',e=>{if(e.key==='Enter'){state.query=e.target.value;render()}});document.querySelectorAll('[data-task]').forEach(b=>b.onclick=()=>{state.doneTasks.has(+b.dataset.task)?state.doneTasks.delete(+b.dataset.task):state.doneTasks.add(+b.dataset.task);render()});document.querySelectorAll('[data-status]').forEach(s=>s.onchange=()=>{state.apps[+s.dataset.status].status=s.value;persist();toast('選考状況を更新しました')});document.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>{state.tab=b.dataset.tab;render()});document.querySelectorAll('[data-compare]').forEach(x=>x.onchange=()=>{if(x.checked){if(state.compareIds.length>=3){x.checked=false;toast('比較できるのは最大3社です');return}state.compareIds.push(x.dataset.compare)}else state.compareIds=state.compareIds.filter(id=>id!==x.dataset.compare);render()});document.querySelector('#compare-btn')?.addEventListener('click',()=>{state.view='compare';render()});document.querySelector('#recalculate')?.addEventListener('click',()=>{toast('プロフィールをもとに推薦を再計算しました');render()});document.querySelector('#edit-profile')?.addEventListener('click',()=>profileModal(false));document.querySelector('#profile-reset')?.addEventListener('click',()=>{if(confirm('プロフィール入力をリセットしますか？')){state.profile={...defaultProfile};persist();render()}});document.querySelector('#new-doc')?.addEventListener('click',()=>toast('新しいESの作成画面を準備中です'));document.querySelectorAll('[data-interview]').forEach(b=>b.onclick=()=>toast('回答エディタを準備中です'));document.querySelector('.mobile-menu')?.addEventListener('click',()=>document.querySelector('.sidebar').classList.toggle('open'))}
function render(){state.view==='dashboard'?dashboard():state.view==='discover'?discover():state.view==='saved'?saved():state.view==='documents'?documents():state.view==='profile'?profile():state.view==='compare'?compare():detail()}render();if(!state.profile.registered)setTimeout(()=>profileModal(true),120);

/* ES / interview preparation layer: kept separate so it can be replaced by an API later. */
const ES_TYPES=[['志望動機','なぜこの会社を志望するのか、事業との接点を教えてください。'],['ガクチカ','学生時代に力を入れたことを教えてください。'],['自己PR','あなたの強みを、経験と成果を交えて教えてください。'],['強み・弱み','あなたの強みと弱み、それぞれの活かし方を教えてください。'],['入社後やりたいこと','入社後に実現したいことを教えてください。']];
const INTERVIEW_TYPES=['志望理由','なぜこの業界か','なぜこの会社か','学生時代に力を入れたこと','強み・弱み','チーム経験','困難を乗り越えた経験','将来やりたいこと','逆質問'];
const rawDocs=safeJSON('codra_es_documents',[]),rawAnswers=safeJSON('codra_interview_answers',{});
state.esDocs=Array.isArray(rawDocs)?rawDocs.filter(x=>x&&x.id&&company(x.companyId)).map(x=>({...x,draft:typeof x.draft==='string'?x.draft:'',status:['未着手','下書き','改善中','完成'].includes(x.status)?x.status:'未着手',aiFeedback:x.aiFeedback&&typeof x.aiFeedback==='object'?x.aiFeedback:null,updatedAt:x.updatedAt||null})):[];state.interviewAnswers=rawAnswers&&typeof rawAnswers==='object'&&!Array.isArray(rawAnswers)?rawAnswers:{};state.activeDoc=null;state.activeInterview=null;
function prepPersist(){try{localStorage.setItem('codra_es_documents',JSON.stringify(state.esDocs));localStorage.setItem('codra_interview_answers',JSON.stringify(state.interviewAnswers))}catch{toast('ES・面接メモを保存できませんでした')}}
function generateEsFeedback(profile,company,draft){const text=String(draft||'').trim();const words=text.length;const strength=profile.strengths||'経験を活かして課題を改善する力';const activity=profile.activities||'学生時代の活動';return{improved:text?`${text}\n\n${company.name}の${company.detail}に魅力を感じています。${activity}で培った${strength}を活かし、入社後は事業とユーザーの変化を捉えながら、具体的な価値づくりに貢献したいです。`:`${company.name}の${company.detail}に魅力を感じています。${activity}で培った${strength}を活かし、入社後は事業とユーザーの変化を捉えながら、具体的な価値づくりに貢献したいです。`,good:[words>80?'経験と志望理由が文章に含まれています':'企業を選んだ理由の方向性が見えています',company.requiredSkills?.length?'企業で活かせるスキルとの接続があります':'自分の強みを言語化しようとしています'],weak:[words<120?'行動・成果の具体的な数字を追加すると説得力が上がります':'文章を短く区切り、結論を冒頭に置くと読みやすくなります',`「なぜ${company.name}なのか」を競合との違いまで深掘りできそうです`],episodes:[`${activity}で、あなたが取った行動と変化した数値`,`${company.name}の事業に関心を持ったきっかけ`],connection:[`${company.name}の${company.jobTypes?.[0]||'仕事'}で${strength}をどう再現するか`,`希望する${profile.industries?.[0]||'業界'}と企業の事業の接点`],questions:[`その経験で、なぜその行動を選びましたか？`,`成果を数字で説明できますか？`,`他社ではなく${company.name}で実現したい理由は？`]}}
function docFor(id){return state.esDocs.find(x=>x.id===id)}
function newDoc(companyId,type){const c=company(companyId)||companies[0],t=ES_TYPES.find(x=>x[0]===type)||ES_TYPES[0];return{id:`es-${Date.now()}`,companyId:c.id,type:t[0],question:t[1],draft:'',aiFeedback:null,updatedAt:new Date().toISOString(),status:'未着手'}}
function editEs(docId){const d=docFor(docId);if(!d)return;const c=company(d.companyId)||companies[0];state.activeDoc=docId;layout(`<button class="back" data-prep-back>← ES一覧へ戻る</button><div class="eyebrow">ES writing studio</div><div class="editor-heading"><div><h1 class="page-title">${d.type}</h1><p class="page-desc">${c.name} · ${d.question}</p></div><span class="save-state">${d.updatedAt?`最終更新 ${new Date(d.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'未保存'}</span></div><div class="grid grid-2 editor-grid"><div class="card"><label class="form-label">設問文<input class="input" id="es-question" value="${d.question}"/></label><label class="form-label">下書き本文<textarea class="textarea es-draft" id="es-draft" rows="14" placeholder="経験・行動・結果・企業との接点を入力してください">${d.draft||''}</textarea></label><div class="editor-footer"><span id="char-count">${String(d.draft||'').length}文字</span><select class="select compact-select" id="es-status">${['未着手','下書き','改善中','完成'].map(x=>`<option ${d.status===x?'selected':''}>${x}</option>`).join('')}</select><button class="secondary-btn" id="save-es">下書きを保存</button><button class="primary-btn" id="improve-es">AIで改善</button></div></div><div class="card feedback-card"><div class="section-head" style="margin:0 0 12px"><div><h3>AI改善案</h3><p>モック提案 · 必ず自分の言葉に編集してください</p></div></div>${d.aiFeedback?feedbackHtml(d.aiFeedback):`<div class="empty compact-empty"><strong>まだ改善案がありません</strong><p>下書きを入力して「AIで改善」を押すと、企業情報・プロフィールをもとに提案します。</p></div>`}</div></div>`);bindEditor(d,c)}
function feedbackHtml(f){return `<div class="feedback-block"><h4>改善版の文章</h4><textarea class="textarea" id="improved-text" rows="8">${f.improved}</textarea><h4>良い点</h4><ul class="bullet-list">${f.good.map(x=>`<li>${x}</li>`).join('')}</ul><h4>弱い点</h4><ul class="bullet-list">${f.weak.map(x=>`<li>${x}</li>`).join('')}</ul><h4>追加すべき具体エピソード</h4><ul class="bullet-list">${f.episodes.map(x=>`<li>${x}</li>`).join('')}</ul><h4>企業との接続ポイント</h4><ul class="bullet-list">${f.connection.map(x=>`<li>${x}</li>`).join('')}</ul><h4>面接で深掘りされそうな質問</h4><ul class="bullet-list">${f.questions.map(x=>`<li>${x}</li>`).join('')}</ul><button class="secondary-btn" id="save-feedback">改善版を保存</button></div>`}
function bindEditor(d,c){const draft=document.querySelector('#es-draft');draft.oninput=()=>document.querySelector('#char-count').textContent=`${draft.value.length}文字`;document.querySelector('[data-prep-back]').onclick=()=>{state.view='documents';state.activeDoc=null;render()};document.querySelector('#save-es').onclick=()=>{d.question=document.querySelector('#es-question').value;d.draft=draft.value;d.status=document.querySelector('#es-status').value;d.updatedAt=new Date().toISOString();prepPersist();toast('ES下書きを保存しました');editEs(d.id)};document.querySelector('#improve-es').onclick=()=>{d.question=document.querySelector('#es-question').value;d.draft=draft.value;d.status='改善中';d.aiFeedback=generateEsFeedback(state.profile,c,d.draft);d.updatedAt=new Date().toISOString();prepPersist();toast('AI改善案を作成しました');editEs(d.id)};document.querySelector('#save-feedback')?.addEventListener('click',()=>{d.aiFeedback.improved=document.querySelector('#improved-text').value;d.updatedAt=new Date().toISOString();prepPersist();toast('AI改善案を保存しました');editEs(d.id)})}
function interviewPrep(companyId){const c=company(companyId)||companies[0];state.activeInterview=c.id;layout(`<button class="back" data-prep-back>← ES・面接対策へ戻る</button><div class="eyebrow">Interview preparation</div><h1 class="page-title">${c.name} 面接対策</h1><p class="page-desc">企業情報とあなたのプロフィールから、質問の意図と回答の型を整理します。</p><div class="notice">質問はサンプルです。実際の選考内容は最新の公式情報や体験談で確認してください。</div><div class="interview-layout"><div class="card interview-questions">${INTERVIEW_TYPES.map((q,i)=>`<button class="question-item ${i===0?'active':''}" data-question="${i}"><span>${i+1}</span>${q}<small>${state.interviewAnswers[`${c.id}-${i}`]?.answer?'回答済み':'未回答'}</small></button>`).join('')}</div><div id="interview-panel" class="card"></div></div>`);renderInterviewPanel(c,0);document.querySelector('[data-prep-back]').onclick=()=>{state.view='documents';state.activeInterview=null;render()};document.querySelectorAll('[data-question]').forEach(b=>b.onclick=()=>{document.querySelectorAll('[data-question]').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderInterviewPanel(c,+b.dataset.question)})}
function renderInterviewPanel(c,index){const q=INTERVIEW_TYPES[index],key=`${c.id}-${index}`,a=state.interviewAnswers[key]||{};const intent=index===0?'志望理由と企業理解の深さを確認する':index===1?'業界への関心が一時的でないか確認する':index===2?'企業固有の志望理由があるか確認する':'経験から学び、再現できる力があるか確認する';document.querySelector('#interview-panel').innerHTML=`<div class="interview-panel-head"><div><span class="tag tag-blue">想定質問 ${index+1}</span><h3>${q}</h3></div><span class="save-state">${a.updatedAt?'保存済み':'未保存'}</span></div><div class="prep-section"><strong>質問の意図</strong><p>${intent}</p></div><div class="prep-section"><strong>回答の型</strong><p>結論 → 背景/課題 → 自分の行動 → 結果 → 入社後の再現</p></div><label class="form-label">自分の回答メモ<textarea class="textarea" id="answer-note" rows="10" placeholder="回答を入力し、面接で深掘りされても答えられる状態にします">${a.answer||''}</textarea></label><div class="prep-section"><strong>改善ポイント</strong><ul class="bullet-list"><li>最初の一文で結論を伝える</li><li>行動と成果を具体的な数字で説明する</li><li>${c.name}の事業・職種との接点を一つ入れる</li></ul></div><div class="prep-section"><strong>深掘り質問</strong><ul class="bullet-list"><li>その判断をした理由は何ですか？</li><li>周囲からはどのような反応がありましたか？</li><li>入社後にどう再現できますか？</li></ul></div><button class="primary-btn" id="save-answer">回答メモを保存</button>`;document.querySelector('#save-answer').onclick=()=>{state.interviewAnswers[key]={answer:document.querySelector('#answer-note').value,updatedAt:new Date().toISOString()};prepPersist();toast('面接回答メモを保存しました');interviewPrep(c.id)}}

function documents(){const docs=state.esDocs;const byCompany=state.saved.size?[...state.saved].map(id=>company(id)).filter(Boolean):[];layout(`<div class="eyebrow">Your preparation</div><h1 class="page-title">ES・面接対策</h1><p class="page-desc">企業情報とあなたの経験を、伝わる言葉に変えていきます。</p><div class="section-head"><div><h2>企業ごとの選考準備</h2><p>保存企業の準備状況を一覧できます</p></div><button class="primary-btn" id="new-es">＋ ESを作る</button></div><div class="grid grid-3 prep-dashboard">${byCompany.length?byCompany.map(c=>{const cd=docs.filter(d=>d.companyId===c.id),answers=INTERVIEW_TYPES.filter((_,i)=>state.interviewAnswers[`${c.id}-${i}`]?.answer).length,appData=state.apps.find(a=>a.company===c.id);return `<div class="card prep-company-card">${logo(c)}<h3>${c.name}</h3><div class="metric-list"><div class="metric"><span>ES完成度</span><b>${cd.length?Math.round(cd.filter(d=>d.status==='完成').length/cd.length*100):0}%</b></div><div class="metric"><span>面接回答準備数</span><b>${answers}/${INTERVIEW_TYPES.length}</b></div></div><p class="company-meta">次の締切：${appData?.deadline||'未登録'}</p><p class="prep-today">今日やるべき準備：${cd.find(d=>d.status!=='完成')?'ESの下書きを更新':'面接回答を1つ練習'}</p><div class="section-actions"><button class="secondary-btn" data-new-es-company="${c.id}">ESを作成</button><button class="link-btn" data-interview-company="${c.id}">面接対策 →</button></div></div>`}).join(''):`<div class="card empty"><strong>保存企業がありません</strong>企業を保存すると、企業ごとの準備状況が表示されます。</div>`}</div><div class="section-head"><div><h2>ESドキュメント</h2><p>下書き・AI改善案はブラウザに保存されています</p></div></div><div class="card">${docs.length?docs.map(d=>{const c=company(d.companyId)||companies[0];return `<div class="doc-item"><div><div class="doc-kind">${d.type} · ${c.name}</div><div class="doc-title">${d.question}</div><div class="doc-meta">${d.draft.length}文字 · ${d.updatedAt?new Date(d.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'}):'未保存'}</div></div><div class="section-actions"><span class="tag ${d.status==='完成'?'tag-green':d.status==='改善中'?'tag-amber':'tag-blue'}">${d.status}</span><button class="link-btn" data-edit-es="${d.id}">編集 →</button></div></div>`}).join(''):`<div class="empty"><strong>まだESを作成していません</strong>「ESを作る」から企業と設問タイプを選択してください。</div>`}</div>`)}
function esCreateModal(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<div class="modal" role="dialog" aria-modal="true"><button class="modal-close" id="es-modal-close" aria-label="閉じる">×</button><div class="eyebrow">ES writing studio</div><h2>作成するESを選ぶ</h2><p class="modal-desc">企業と設問タイプを選択すると編集画面が開きます。</p><label class="form-label">企業<select class="select" id="new-es-company">${companies.map(c=>`<option value="${c.id}">${c.name}</option>`).join('')}</select></label><label class="form-label">設問タイプ<select class="select" id="new-es-type">${ES_TYPES.map(x=>`<option>${x[0]}</option>`).join('')}</select></label><div class="modal-actions"><button class="secondary-btn" id="es-cancel">キャンセル</button><button class="primary-btn" id="create-es">作成する</button></div></div>`;document.body.appendChild(modal);modal.querySelector('#es-modal-close').onclick=()=>modal.remove();modal.querySelector('#es-cancel').onclick=()=>modal.remove();modal.querySelector('#create-es').onclick=()=>{const d=newDoc(modal.querySelector('#new-es-company').value,modal.querySelector('#new-es-type').value);state.esDocs.unshift(d);prepPersist();modal.remove();editEs(d.id)}}
function bind(){document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{state.view=b.dataset.view;state.companyId=null;render()});document.querySelectorAll('[data-save]').forEach(b=>b.onclick=()=>{const id=b.dataset.save;state.saved.has(id)?state.saved.delete(id):state.saved.add(id);persist();toast(state.saved.has(id)?'企業を保存しました':'保存を解除しました');render()});document.querySelectorAll('.detail-link').forEach(b=>b.onclick=()=>{state.companyId=b.dataset.company;state.view='detail';state.tab='overview';render()});document.querySelectorAll('[data-filter]').forEach(b=>b.onclick=()=>{state.filter=b.dataset.filter;render()});document.querySelector('#search-btn')?.addEventListener('click',()=>{state.query=document.querySelector('#company-search').value;render()});document.querySelector('#company-search')?.addEventListener('keydown',e=>{if(e.key==='Enter'){state.query=e.target.value;render()}});document.querySelectorAll('[data-task]').forEach(b=>b.onclick=()=>{state.doneTasks.has(+b.dataset.task)?state.doneTasks.delete(+b.dataset.task):state.doneTasks.add(+b.dataset.task);render()});document.querySelectorAll('[data-status]').forEach(s=>s.onchange=()=>{state.apps[+s.dataset.status].status=s.value;persist();toast('選考状況を更新しました')});document.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>{state.tab=b.dataset.tab;render()});document.querySelectorAll('[data-compare]').forEach(x=>x.onchange=()=>{if(x.checked){if(state.compareIds.length>=3){x.checked=false;toast('比較できるのは最大3社です');return}state.compareIds.push(x.dataset.compare)}else state.compareIds=state.compareIds.filter(id=>id!==x.dataset.compare);render()});document.querySelector('#compare-btn')?.addEventListener('click',()=>{state.view='compare';render()});document.querySelector('#recalculate')?.addEventListener('click',()=>{toast('プロフィールをもとに推薦を再計算しました');render()});document.querySelector('#edit-profile')?.addEventListener('click',()=>profileModal(false));document.querySelector('#profile-reset')?.addEventListener('click',()=>{if(confirm('プロフィール入力をリセットしますか？')){state.profile={...defaultProfile};persist();render()}});document.querySelector('#new-es')?.addEventListener('click',esCreateModal);document.querySelectorAll('[data-new-es-company]').forEach(b=>b.onclick=()=>{const d=newDoc(b.dataset.newEsCompany,'志望動機');state.esDocs.unshift(d);prepPersist();editEs(d.id)});document.querySelectorAll('[data-edit-es]').forEach(b=>b.onclick=()=>editEs(b.dataset.editEs));document.querySelectorAll('[data-interview-company]').forEach(b=>b.onclick=()=>interviewPrep(b.dataset.interviewCompany));document.querySelector('.mobile-menu')?.addEventListener('click',()=>document.querySelector('.sidebar').classList.toggle('open'))}
render();

// Keep the migration preview available even when the later compatibility data manager is used.
const dataManagerForE2E = dataManager;
dataManager = function(){
  dataManagerForE2E();
  const modal=document.querySelector('.data-modal');
  if(!modal||modal.querySelector('.migration-preview'))return;
  const summary=migrationSummary();
  const panel=document.createElement('div');
  panel.className='migration-preview';
  panel.innerHTML=`<div class="section-head" style="margin:0 0 10px"><div><h3>Supabase移行プレビュー</h3><p>実際のアップロードはまだ行いません。</p></div><span class="tag tag-amber">準備中</span></div><div class="migration-grid">${summary.map(([label,count])=>`<div><span>${label}</span><strong>${count}件</strong></div>`).join('')}</div>`;
  modal.querySelector('.data-danger')?.before(panel);
};

/* Demo experience layer: seed data is clearly marked and removable. */
const DEMO_KEYS={active:'codra_demo_active',saved:'codra_demo_saved_companies',guide:'codra_demo_guide_closed'};
const demoProfile={...defaultProfile,registered:true,updatedAt:new Date().toISOString(),nickname:'デモユーザー',industries:['IT・Web','人材'],jobTypes:['事業企画','マーケティング'],locations:['東京'],strengths:'課題を見つけ、周囲を巻き込みながら改善できる',skills:'企画、データ分析、英語',activities:'学園祭チームで来場者導線を改善し、参加率を向上させた'};
function demoPayload(){return{profile:{...demoProfile,isDemo:true},saved:['mercari','recruit','layerx'],apps:[{company:'mercari',status:'ES作成中',deadline:'2026-07-18',next:'志望動機を仕上げる',priority:'高',isDemo:true},{company:'recruit',status:'一次面接',deadline:'2026-07-24',next:'過去質問を確認',priority:'中',isDemo:true},{company:'layerx',status:'応募予定',deadline:'2026-08-02',next:'社員訪問を探す',priority:'中',isDemo:true}],docs:[{id:'demo-es-1',companyId:'mercari',type:'志望動機',question:'なぜこの会社を志望するのか、事業との接点を教えてください。',draft:'ユーザーの生活をより便利にするサービスを、仮説検証しながらつくりたいと考えています。',status:'改善中',updatedAt:new Date().toISOString(),isDemo:true,aiFeedback:{improved:'ユーザー起点で仮説検証を重ね、生活の選択肢を広げるサービスをつくりたいと考えています。学園祭チームで来場者導線を改善した経験を活かし、ユーザーの行動変化を捉えながら価値提供に貢献します。',good:['企業の事業との接点がある','経験を職種に接続できている'],weak:['成果を数字で補足するとさらに伝わる'],episodes:['導線改善前後の参加率や行動変化'],connection:['ユーザー起点の改善経験とプロダクト開発'],questions:['なぜその改善案を選びましたか？'],warnings:[],source:'mock',generatedAt:new Date().toISOString()}},{id:'demo-es-2',companyId:'recruit',type:'自己PR',question:'あなたの強みを、経験と成果を交えて教えてください。',draft:'私の強みは、周囲を巻き込みながら課題を前に進める力です。',status:'下書き',updatedAt:new Date().toISOString(),isDemo:true,aiFeedback:null}],answers:{'mercari-0':{answer:'結論から話し、経験・行動・結果の順で整理します。',updatedAt:new Date().toISOString(),isDemo:true},'recruit-1':{answer:'人の選択肢を広げる事業に関心があります。',updatedAt:new Date().toISOString(),isDemo:true}},aiFeedback:{'mercari-0':{betterAnswer:'ユーザー起点で改善を進めた経験を、入社後のプロダクト改善に再現したいです。',strengths:['結論を意識している'],improvements:['成果を数字で補足する'],questions:['その行動の成果は何ですか？'],structure:'結論 → 行動 → 結果 → 再現',warnings:[],source:'mock',generatedAt:new Date().toISOString(),isDemo:true}},notes:{mercari:{note:'プロダクトとユーザー体験に関する企業研究メモです。',updatedAt:new Date().toISOString(),isDemo:true}}}}
function hasDemoData(){return safeJSON(DEMO_KEYS.active,false)===true||state.profile?.isDemo===true||state.apps.some(x=>x?.isDemo)||state.esDocs.some(x=>x?.isDemo)}
function seedDemo(){const d=demoPayload();state.profile=d.profile;state.saved=new Set(d.saved);state.apps=d.apps;state.esDocs=d.docs;state.interviewAnswers=d.answers;state.interviewAiFeedback=d.aiFeedback;state.researchNotes=d.notes;state.usingDemoSaved=false;state.usingDemoApps=false;try{dataStore.saveProfile(state.profile);dataStore.saveSavedCompanies(d.saved);dataStore.saveApplications(d.apps);dataStore.saveEsDocuments(d.docs);dataStore.saveInterviewAnswers(d.answers);dataStore.saveResearchNotes(d.notes);localStorage.setItem(STORAGE_KEYS.interviewAiFeedback,JSON.stringify(d.aiFeedback));localStorage.setItem(DEMO_KEYS.active,'true');localStorage.setItem(DEMO_KEYS.saved,JSON.stringify(d.saved));localStorage.removeItem(DEMO_KEYS.guide);toast('デモデータを読み込みました');render()}catch{toast('デモデータを読み込めませんでした')}}
function startDemo(){const counts=userCounts();if(counts.profile||counts.saved||counts.apps||counts.es||counts.answers){confirmDataAction('デモデータを読み込みますか？','現在のプロフィール、保存企業、選考、ES、面接メモをデモデータで置き換えます。',seedDemo)}else seedDemo()}
function deleteDemo(){confirmDataAction('デモデータを削除しますか？','デモとして追加されたプロフィール、企業、選考、ES、面接、AI結果、企業研究メモだけを削除します。',()=>{const demoIds=new Set(safeJSON(DEMO_KEYS.saved,[]));state.profile?.isDemo&&(state.profile={...defaultProfile});state.saved=new Set([...state.saved].filter(id=>!demoIds.has(id)));state.apps=state.apps.filter(x=>!x.isDemo);state.esDocs=state.esDocs.filter(x=>!x.isDemo);state.interviewAnswers=Object.fromEntries(Object.entries(state.interviewAnswers).filter(([,x])=>!x?.isDemo));state.interviewAiFeedback=Object.fromEntries(Object.entries(state.interviewAiFeedback).filter(([,x])=>!x?.isDemo));state.researchNotes=Object.fromEntries(Object.entries(state.researchNotes).filter(([,x])=>!x?.isDemo));persist();prepPersist();try{localStorage.removeItem(DEMO_KEYS.active);localStorage.removeItem(DEMO_KEYS.saved);localStorage.removeItem(STORAGE_KEYS.interviewAiFeedback)}catch{}toast('デモデータを削除しました');render()})}
