document.addEventListener('click',e=>{if(e.target?.id==='close-demo-guide'){try{localStorage.setItem(DEMO_KEYS.guide,'true')}catch{}e.target.closest('.demo-guide')?.remove();toast('ガイドを閉じました')}});
document.addEventListener('click',e=>{const guideClose=e.target.closest?.('#close-demo-guide');if(guideClose){try{localStorage.setItem(DEMO_KEYS.guide,'true')}catch{}guideClose.closest('.demo-guide')?.remove();toast('ガイドを閉じました')}});
