const dataStore={getProfile(){return safeJSON(STORAGE_KEYS.profile,defaultProfile)},saveProfile(profile){localStorage.setItem(STORAGE_KEYS.profile,JSON.stringify(profile))},getSavedCompanies(){const x=safeJSON(STORAGE_KEYS.savedCompanies,[]);return Array.isArray(x)?x:[]},saveSavedCompanies(ids){localStorage.setItem(STORAGE_KEYS.savedCompanies,JSON.stringify(ids))},getApplications(){const x=safeJSON(STORAGE_KEYS.applications,[]);return Array.isArray(x)?x:[]},saveApplications(items){localStorage.setItem(STORAGE_KEYS.applications,JSON.stringify(items))},getEsDocuments(){const x=safeJSON(STORAGE_KEYS.esDocuments,[]);return Array.isArray(x)?x:[]},saveEsDocuments(items){localStorage.setItem(STORAGE_KEYS.esDocuments,JSON.stringify(items))},getInterviewAnswers(){const x=safeJSON(STORAGE_KEYS.interviewAnswers,{});return x&&typeof x==='object'&&!Array.isArray(x)?x:{}},saveInterviewAnswers(items){localStorage.setItem(STORAGE_KEYS.interviewAnswers,JSON.stringify(items))},getResearchNotes(){const x=safeJSON(STORAGE_KEYS.researchNotes,{});return x&&typeof x==='object'&&!Array.isArray(x)?x:{}},saveResearchNotes(notes){localStorage.setItem(STORAGE_KEYS.researchNotes,JSON.stringify(notes))},exportAll(){return{version:1,exportedAt:new Date().toISOString(),codra_profile:this.getProfile(),codra_saved_companies:this.getSavedCompanies(),codra_apps:this.getApplications(),codra_es_documents:this.getEsDocuments(),codra_interview_answers:this.getInterviewAnswers(),codra_company_research_notes:this.getResearchNotes()}},importAll(snapshot){validateImport(snapshot);if(snapshot.codra_profile!==undefined)this.saveProfile(snapshot.codra_profile);if(snapshot.codra_saved_companies!==undefined)this.saveSavedCompanies(snapshot.codra_saved_companies);if(snapshot.codra_apps!==undefined)this.saveApplications(snapshot.codra_apps);if(snapshot.codra_es_documents!==undefined)this.saveEsDocuments(snapshot.codra_es_documents);if(snapshot.codra_interview_answers!==undefined)this.saveInterviewAnswers(snapshot.codra_interview_answers);if(snapshot.codra_company_research_notes!==undefined)this.saveResearchNotes(snapshot.codra_company_research_notes)}};
