function storageSettingsHtml(){const s=state.storageSettings;return `<div class="storage-panel"><div class="section-head" style="margin:0 0 10px"><div><h3>保存先</h3><p>現在はブラウザ内のlocalStorageのみを使用しています。</p></div><span class="tag tag-blue">localStorage</span></div><div class="storage-route"><span>現在の保存先</span><strong>ブラウザ localStorage</strong><span>将来の保存先</span><strong>Supabase</strong></div><div class="form-grid"><label class="form-label">将来用プロバイダー<select class="select" id="storage-provider"><option value="localStorage" ${s.provider==='localStorage'?'selected':''}>localStorage</option><option value="supabase" ${s.provider==='supabase'?'selected':''}>Supabase（準備中）</option></select></label><label class="form-label">Supabase URL<input class="input" id="storage-supabase-url" value="${s.supabaseUrl||''}" placeholder="https://your-project.supabase.co"/></label></div><label class="check-line"><input type="checkbox" id="storage-sync" ${s.syncEnabled?'checked':''}/> 将来のSupabase同期を有効にする（現在は未接続）</label><button class="secondary-btn" id="save-storage-settings">保存先設定を保存</button></div>`}
function dataManager(){const x=userCounts(),summary=migrationSummary();const m=document.createElement('div');m.className='modal-backdrop';m.innerHTML=`<div class="modal data-modal" role="dialog" aria-modal="true" aria-labelledby="data-title"><button class="modal-close" id="data-close" aria-label="閉じる">×</button><div class="eyebrow">Data management</div><h2 id="data-title">データ管理</h2><p class="modal-desc">保存データの確認、バックアップ、将来のSupabase移行準備ができます。</p><div class="data-summary">${[['プロフィール',x.profile?'作成済み':'未作成'],['保存企業',`${x.saved}社`],['選考管理',`${x.apps}件`],['ES下書き',`${x.es}件`],['面接メモ',`${x.answers}件`]].map(([a,b])=>`<div><small>${a}</small><strong>${b}</strong></div>`).join('')}</div><div class="data-actions"><button class="secondary-btn" id="export-json">JSONをダウンロード</button><button class="secondary-btn" id="copy-json">JSONをコピー</button><button class="secondary-btn" id="import-json">JSONを読み込む</button></div><textarea class="textarea data-textarea" id="data-json" rows="7" placeholder="エクスポートしたJSONを貼り付けてください"></textarea><p class="data-note">不正なJSONや対象外データは反映せず、既存データを保持します。</p>${storageSettingsHtml()}<div class="migration-preview"><div class="section-head" style="margin:0 0 10px"><div><h3>Supabase移行プレビュー</h3><p>実際のアップロードはまだ行いません。</p></div><span class="tag tag-amber">準備中</span></div><div class="migration-grid">${summary.map(([label,count])=>`<div><span>${label}</span><strong>${count}件</strong></div>`).join('')}</div></div><div class="data-danger"><button class="secondary-btn" id="reset-user">ユーザーデータをリセット</button><button class="secondary-btn danger-btn" id="reset-all">全データをリセット</button></div></div>`;document.body.appendChild(m);const close=()=>m.remove();m.querySelector('#data-close').onclick=close;m.querySelector('#export-json').onclick=()=>{const text=JSON.stringify(dataStore.exportAll(),null,2);m.querySelector('#data-json').value=text;const blob=new Blob([text],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`codra-data-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(a.href);toast('データを書き出しました')};m.querySelector('#copy-json').onclick=async()=>{const text=JSON.stringify(dataStore.exportAll(),null,2);m.querySelector('#data-json').value=text;try{await navigator.clipboard.writeText(text);toast('JSONをコピーしました')}catch{toast('コピーできませんでした。テキスト欄からコピーしてください')}};m.querySelector('#import-json').onclick=()=>{try{const snapshot=JSON.parse(m.querySelector('#data-json').value);dataStore.importAll(snapshot);applySnapshot(snapshot);close();toast('データを読み込みました');render()}catch(e){toast(`読み込みエラー：${e.message}`)}};m.querySelector('#save-storage-settings').onclick=()=>{state.storageSettings={provider:m.querySelector('#storage-provider').value,supabaseUrl:m.querySelector('#storage-supabase-url').value.trim(),syncEnabled:m.querySelector('#storage-sync').checked};try{localStorage.setItem(STORAGE_KEYS.storageSettings,JSON.stringify(state.storageSettings));toast('保存先設定を保存しました')}catch{toast('保存先設定を保存できませんでした')}};m.querySelector('#reset-user').onclick=()=>confirmDataAction('ユーザーデータをリセットしますか？','プロフィール、保存企業、選考、ES、面接メモ、AIフィードバックを削除します。サンプル企業は残ります。',()=>{[STORAGE_KEYS.profile,STORAGE_KEYS.savedCompanies,STORAGE_KEYS.applications,STORAGE_KEYS.esDocuments,STORAGE_KEYS.interviewAnswers,STORAGE_KEYS.researchNotes,STORAGE_KEYS.interviewAiFeedback].forEach(k=>{try{localStorage.removeItem(k)}catch{}});state.profile={...defaultProfile};state.saved=new Set();state.apps=[];state.esDocs=[];state.interviewAnswers={};state.researchNotes={};state.interviewAiFeedback={};close();toast('ユーザーデータをリセットしました');render()});m.querySelector('#reset-all').onclick=()=>confirmDataAction('全データをリセットしますか？','対象localStorageデータをすべて削除します。この操作は取り消せません。',()=>{DATA_KEYS.concat([STORAGE_KEYS.aiSettings,STORAGE_KEYS.aiConsent,STORAGE_KEYS.interviewAiFeedback,STORAGE_KEYS.storageSettings]).forEach(k=>{try{localStorage.removeItem(k)}catch{}});state.profile={...defaultProfile};state.saved=new Set();state.apps=[];state.esDocs=[];state.interviewAnswers={};state.researchNotes={};state.interviewAiFeedback={};close();toast('全データをリセットしました');render()})}

