function buildEsPrompt(profile,company,doc,researchNote){return{type:'es_feedback',profile,company,input:{documentType:doc.type,question:doc.question,draft:doc.draft},researchNote:researchNote||{},model:getAiSettings().model}}
function buildInterviewPrompt(profile,company,question,answer,researchNote){return{type:'interview_feedback',profile,company,input:{question,answer},researchNote:researchNote||{},model:getAiSettings().model}}
async function requestAiCompletion(payload){const settings=getAiSettings();if(!settings.endpoint)throw Error('APIエンドポイントが未設定です。AI設定でサーバー側プロキシのURLを入力してください。');const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),settings.timeout*1000);try{const res=await fetch(settings.endpoint,{method:'POST',headers:{'Content-Type':'application/json'},credentials:'omit',body:JSON.stringify(payload),signal:controller.signal});if(!res.ok)throw Error(`AIサーバーがエラーを返しました（${res.status}）`);const body=await res.json();if(!body||typeof body!=='object')throw Error('AIサーバーのレスポンス形式が不正です');return body}catch(e){if(e.name==='AbortError')throw Error(`AI生成がタイムアウトしました（${settings.timeout}秒）`);if(e instanceof TypeError)throw Error('AIサーバーに接続できませんでした。エンドポイントとネットワークを確認してください。');throw e}finally{clearTimeout(timer)}}
function normalizeEsFeedback(response){const x=response?.result||response||{};return{improved:x.improvedText||x.improved||'',good:x.goodPoints||x.good||[],weak:x.weakPoints||x.weak||[],episodes:x.addEpisodes||x.episodes||[],connection:x.companyConnection||x.connection||[],questions:x.followUpQuestions||x.questions||[],warnings:x.warnings||[]}}
function normalizeInterviewFeedback(response){const x=response?.result||response||{};return{betterAnswer:x.betterAnswer||x.improvedAnswer||'',strengths:x.strengths||[],improvements:x.improvements||[],questions:x.followUpQuestions||[],structure:x.answerStructure||'',warnings:x.warnings||[]}}
async function generateEsFeedback(profile,company,draft,options={}){const doc=options.doc||{type:options.type||'ES',question:options.question||'',draft};const settings=getAiSettings();if(settings.mode==='api'){const response=await requestAiCompletion(buildEsPrompt(profile,company,doc,options.researchNote)),normalized=normalizeEsFeedback(response);if(!normalized.improved||!Array.isArray(normalized.good)||!Array.isArray(normalized.weak))throw Error('AIレスポンスの形式が不正です。もう一度お試しください。');return{...normalized,source:'api',generatedAt:new Date().toISOString()}}const mock=window.__codraMockEs?window.__codraMockEs(profile,company,draft):{improved:`${draft||''}\n\n${company.name}の${company.detail}に魅力を感じています。${profile.activities||'学生時代の活動'}で培った${profile.strengths||'課題を改善する力'}を活かし、事業に貢献したいです。`,good:['経験と志望理由の方向性が見えています','企業の事業との接点を作れています'],weak:['行動と成果を数字で具体化すると説得力が上がります','なぜこの会社なのかを競合との差分まで深掘りしましょう'],episodes:[`${profile.activities||'活動'}で自分が取った行動と成果の数字`,'企業の事業に関心を持った具体的なきっかけ'],connection:[`${company.name}の${company.jobTypes?.[0]||'仕事'}で強みをどう再現するか`],questions:[`なぜその行動を選びましたか？`,`他社ではなく${company.name}を選ぶ理由は？`]};return{...normalizeEsFeedback(mock),source:'mock',generatedAt:new Date().toISOString()}}
async function generateInterviewFeedback(profile,company,question,answer,options={}){const settings=getAiSettings();if(settings.mode==='api'){const response=await requestAiCompletion(buildInterviewPrompt(profile,company,question,answer,options.researchNote)),normalized=normalizeInterviewFeedback(response);if(!normalized.betterAnswer||!Array.isArray(normalized.strengths)||!Array.isArray(normalized.improvements))throw Error('AIレスポンスの形式が不正です。もう一度お試しください。');return{...normalized,source:'api',generatedAt:new Date().toISOString()}}return{betterAnswer:answer?`${answer}\n\n結論を先に述べ、${company.name}で${company.jobTypes?.[0]||'この仕事'}にどう活かすかまでつなげます。`:'まず結論を一文で述べ、背景・行動・結果・入社後の再現の順で整理しましょう。',strengths:answer?['自分の経験を言葉にしようとしています','質問に対する材料があります']:['回答の型を意識しようとしています'],improvements:['最初に結論を置く','行動と成果を具体的な数字で説明する',`${company.name}の事業との接点を一つ追加する`],questions:['その判断をした理由は何ですか？','周囲からはどのような反応がありましたか？','入社後にどう再現できますか？'],structure:'結論 → 背景/課題 → 自分の行動 → 結果 → 入社後の再現',warnings:[],source:'mock',generatedAt:new Date().toISOString()}}
function aiSourceLabel(source){return `<span class="ai-source ${source==='api'?'api-source':'mock-source'}">${source==='api'?'API生成':'モック生成'}</span>`}
function aiConsent(){if(state.aiConsent||getAiSettings().mode!=='api')return Promise.resolve(true);return new Promise(resolve=>{const m=document.createElement('div');m.className='modal-backdrop';m.innerHTML=`<div class="modal consent-modal" role="dialog" aria-modal="true"><button class="modal-close" id="consent-close" aria-label="閉じる">×</button><div class="eyebrow">Privacy check</div><h2>AIに送信する前に</h2><p class="modal-desc">ESや面接回答には個人情報が含まれる可能性があります。</p><ul class="bullet-list"><li>本番ではサーバー側プロキシで安全に処理してください。</li><li>API接続予定モードでは設定したエンドポイントへ内容を送信します。</li><li>同意した場合のみAI生成を実行します。</li></ul><div class="modal-actions"><button class="secondary-btn" id="consent-no">今回は送信しない</button><button class="primary-btn" id="consent-yes">同意して送信</button></div></div>`;document.body.appendChild(m);const finish=v=>{m.remove();resolve(v)};m.querySelector('#consent-close').onclick=()=>finish(false);m.querySelector('#consent-no').onclick=()=>finish(false);m.querySelector('#consent-yes').onclick=()=>{state.aiConsent=true;try{localStorage.setItem('codra_ai_consent','true')}catch{}finish(true)}})}

state.interviewAiFeedback=safeJSON('codra_interview_ai_feedback',{});if(!state.interviewAiFeedback||typeof state.interviewAiFeedback!=='object'||Array.isArray(state.interviewAiFeedback))state.interviewAiFeedback={};
function aiResultSave(key,value){if(!getAiSettings().saveResults)return;try{state.interviewAiFeedback[key]=value;localStorage.setItem('codra_interview_ai_feedback',JSON.stringify(state.interviewAiFeedback))}catch{}}
function aiFeedbackHtml(f){if(!f)return '<div class="empty compact-empty"><strong>まだAIフィードバックがありません</strong><p>回答を入力して「AIでフィードバック」を押してください。</p></div>';return `<div class="ai-result"><div class="ai-result-head"><h4>AIフィードバック</h4>${aiSourceLabel(f.source)}<small>${new Date(f.generatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}</small></div><h4>改善回答例</h4><textarea class="textarea" id="better-answer" rows="6">${f.betterAnswer||''}</textarea><h4>回答の強み</h4><ul class="bullet-list">${f.strengths.map(x=>`<li>${x}</li>`).join('')}</ul><h4>改善ポイント</h4><ul class="bullet-list">${f.improvements.map(x=>`<li>${x}</li>`).join('')}</ul><h4>深掘り質問</h4><ul class="bullet-list">${f.questions.map(x=>`<li>${x}</li>`).join('')}</ul><h4>回答構成</h4><p class="ai-structure">${f.structure}</p>${f.warnings?.length?`<h4>注意点</h4><ul class="bullet-list">${f.warnings.map(x=>`<li>${x}</li>`).join('')}</ul>`:''}</div>`}
function editEs(docId){const d=docFor(docId);if(!d)return;const c=company(d.companyId)||companies[0];state.activeDoc=docId;layout(`<button class="back" data-prep-back>← ES一覧へ戻る</button><div class="eyebrow">ES writing studio</div><div class="editor-heading"><div><h1 class="page-title">${d.type}</h1><p class="page-desc">${c.name} · ${d.question}</p></div><span class="save-state">${d.updatedAt?`最終更新 ${new Date(d.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'未保存'} ${dataBadge('user')}</span></div><div class="grid grid-2 editor-grid"><div class="card"><label class="form-label">設問文<input class="input" id="es-question" value="${d.question}"/></label><label class="form-label">下書き本文<textarea class="textarea es-draft" id="es-draft" rows="14" placeholder="経験・行動・結果・企業との接点を入力してください">${d.draft||''}</textarea></label><div class="editor-footer"><span id="char-count">${String(d.draft||'').length}文字</span><select class="select compact-select" id="es-status">${['未着手','下書き','改善中','完成'].map(x=>`<option ${d.status===x?'selected':''}>${x}</option>`).join('')}</select><button class="secondary-btn" id="save-es">下書きを保存</button><button class="primary-btn" id="improve-es">AIで改善</button></div><div id="es-ai-status" class="ai-status" aria-live="polite"></div></div><div class="card feedback-card"><div class="section-head" style="margin:0 0 12px"><div><h3>AI改善案</h3><p>モック/ API接続予定モード · 必ず自分の言葉に編集してください</p></div></div>${d.aiFeedback?feedbackHtml({...d.aiFeedback,source:d.aiFeedback.source||'mock',generatedAt:d.aiFeedback.generatedAt||new Date().toISOString()}):`<div class="empty compact-empty"><strong>まだ改善案がありません</strong><p>下書きを入力してAI改善を実行すると、企業情報・プロフィールをもとに提案します。</p></div>`}</div></div>`);bindAiEditor(d,c)}
function bindAiEditor(d,c){const draft=document.querySelector('#es-draft'),status=document.querySelector('#es-ai-status');draft.oninput=()=>document.querySelector('#char-count').textContent=`${draft.value.length}文字`;document.querySelector('[data-prep-back]').onclick=()=>{state.view='documents';render()};document.querySelector('#save-es').onclick=()=>{d.question=document.querySelector('#es-question').value;d.draft=draft.value;d.status=document.querySelector('#es-status').value;d.updatedAt=new Date().toISOString();prepPersist();toast('ES下書きを保存しました');editEs(d.id)};const run=async()=>{const ok=await aiConsent();if(!ok){status.textContent='送信をキャンセルしました';return}const btn=document.querySelector('#improve-es');btn.disabled=true;status.className='ai-status loading';status.textContent='AIが文章を分析しています…';d.question=document.querySelector('#es-question').value;d.draft=draft.value;try{d.aiFeedback=await generateEsFeedback(state.profile,c,d.draft,{doc:d,researchNote:state.researchNotes[c.id]});d.status='改善中';d.updatedAt=new Date().toISOString();if(getAiSettings().saveResults)prepPersist();status.className='ai-status success';status.textContent=`生成しました（${d.aiFeedback.source==='api'?'API':'モック'}）`;editEs(d.id)}catch(e){status.className='ai-status error';status.textContent=e.message||'AI生成に失敗しました。時間を置いて再試行してください。'}finally{btn.disabled=false}};document.querySelector('#improve-es').onclick=run;document.querySelector('#save-feedback')?.addEventListener('click',()=>{d.aiFeedback.improved=document.querySelector('#improved-text').value;d.updatedAt=new Date().toISOString();prepPersist();toast('AI改善案を保存しました');editEs(d.id)});document.querySelector('#apply-es')?.addEventListener('click',()=>confirmDataAction('改善案を下書きに反映しますか？','現在の下書きは改善版で置き換わります。',()=>{d.draft=d.aiFeedback.improved;d.updatedAt=new Date().toISOString();prepPersist();toast('改善案を下書きに反映しました');editEs(d.id)}))}
function feedbackHtml(f){return `<div class="feedback-block"><div class="ai-result-head">${aiSourceLabel(f.source||'mock')}<small>${f.generatedAt?new Date(f.generatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'}):'生成日時不明'}</small></div><h4>改善版の文章</h4><textarea class="textarea" id="improved-text" rows="8">${f.improved||''}</textarea><div class="section-actions"><button class="secondary-btn" id="save-feedback">改善版を保存</button><button class="secondary-btn" id="apply-es">下書きへ反映</button></div><h4>良い点</h4><ul class="bullet-list">${(f.good||[]).map(x=>`<li>${x}</li>`).join('')}</ul><h4>弱い点</h4><ul class="bullet-list">${(f.weak||[]).map(x=>`<li>${x}</li>`).join('')}</ul><h4>追加すべき具体エピソード</h4><ul class="bullet-list">${(f.episodes||[]).map(x=>`<li>${x}</li>`).join('')}</ul><h4>企業との接続ポイント</h4><ul class="bullet-list">${(f.connection||[]).map(x=>`<li>${x}</li>`).join('')}</ul><h4>面接で深掘りされそうな質問</h4><ul class="bullet-list">${(f.questions||[]).map(x=>`<li>${x}</li>`).join('')}</ul>${f.warnings?.length?`<h4>注意点</h4><ul class="bullet-list">${f.warnings.map(x=>`<li>${x}</li>`).join('')}</ul>`:''}</div>`}
function renderInterviewPanel(c,index){const q=INTERVIEW_TYPES[index],key=`${c.id}-${index}`,a=state.interviewAnswers[key]||{},f=state.interviewAiFeedback[key];const intent=index===0?'志望理由と企業理解の深さを確認する':index===1?'業界への関心が一時的でないか確認する':index===2?'企業固有の志望理由があるか確認する':'経験から学び、再現できる力があるか確認する';document.querySelector('#interview-panel').innerHTML=`<div class="interview-panel-head"><div><span class="tag tag-blue">想定質問 ${index+1}</span><h3>${q}</h3></div><span class="save-state">${a.updatedAt?'保存済み':'未保存'}</span></div><div class="prep-section"><strong>質問の意図</strong><p>${intent}</p></div><div class="prep-section"><strong>回答の型</strong><p>結論 → 背景/課題 → 自分の行動 → 結果 → 入社後の再現</p></div><label class="form-label">自分の回答メモ<textarea class="textarea" id="answer-note" rows="9" placeholder="回答を入力し、面接で深掘りされても答えられる状態にします">${a.answer||''}</textarea></label><div class="section-actions"><button class="secondary-btn" id="save-answer">回答メモを保存</button><button class="primary-btn" id="improve-interview">AIでフィードバック</button></div><div id="interview-ai-status" class="ai-status" aria-live="polite"></div><div class="prep-section"><strong>改善ポイント</strong><ul class="bullet-list"><li>最初の一文で結論を伝える</li><li>行動と成果を具体的な数字で説明する</li><li>${c.name}の事業・職種との接点を一つ入れる</li></ul></div>${aiFeedbackHtml(f)}`;document.querySelector('#save-answer').onclick=()=>{state.interviewAnswers[key]={answer:document.querySelector('#answer-note').value,updatedAt:new Date().toISOString()};prepPersist();toast('面接回答メモを保存しました');renderInterviewPanel(c,index)};document.querySelector('#improve-interview').onclick=async()=>{const ok=await aiConsent();if(!ok)return;const btn=document.querySelector('#improve-interview'),status=document.querySelector('#interview-ai-status');btn.disabled=true;status.className='ai-status loading';status.textContent='AIが回答を分析しています…';const answer=document.querySelector('#answer-note').value;try{const result=await generateInterviewFeedback(state.profile,c,q,answer,{researchNote:state.researchNotes[c.id]});aiResultSave(key,result);status.className='ai-status success';status.textContent=`生成しました（${result.source==='api'?'API':'モック'}）`;renderInterviewPanel(c,index)}catch(e){status.className='ai-status error';status.textContent=e.message||'AIフィードバックに失敗しました。再試行してください。'}finally{btn.disabled=false}}}

function aiSettingsHtml(){const s=getAiSettings();return `<div class="card ai-settings-card"><div class="section-head" style="margin:0 0 15px"><div><h2>AI設定</h2><p>APIキーはブラウザに保存せず、サーバー側プロキシで扱います。</p></div><span class="tag ${s.mode==='api'?'tag-amber':'tag-green'}">${s.mode==='api'?'API接続予定':'モック'}</span></div><div class="form-grid"><label class="form-label">AIモード<select class="select" id="ai-mode"><option value="mock" ${s.mode==='mock'?'selected':''}>モック</option><option value="api" ${s.mode==='api'?'selected':''}>API接続予定</option></select></label><label class="form-label">モデル名<input class="input" id="ai-model" value="${s.model}" placeholder="gpt-4o-mini"/></label><label class="form-label">APIエンドポイントURL<input class="input" id="ai-endpoint" value="${s.endpoint}" placeholder="https://your-server.example.com/api/ai"/></label><label class="form-label">タイムアウト秒数<input class="input" type="number" id="ai-timeout" value="${s.timeout}" min="5" max="120"/></label></div><label class="check-line"><input type="checkbox" id="ai-save-results" ${s.saveResults?'checked':''}/> 生成結果をlocalStorageに保存する</label><div class="ai-safety-note">ESや面接回答には個人情報が含まれる可能性があります。APIモードでは設定したエンドポイントへ送信されるため、同意した場合のみ生成します。本番では認証済みのサーバー側プロキシを使用してください。</div><button class="primary-btn" id="save-ai-settings">AI設定を保存</button></div>`}
function profile(){const p=state.profile;layout(`<div class="eyebrow">Profile intelligence</div><h1 class="page-title">プロフィール分析</h1><p class="page-desc">入力した情報から見えた、現時点のキャリア仮説です。</p><div class="section-actions profile-actions"><button class="primary-btn" id="edit-profile">プロフィールを編集</button><button class="secondary-btn" id="profile-reset">入力をリセット</button><button class="secondary-btn" id="open-data">データ管理</button></div><div class="notice">AIの提案は仮説です。企業情報はサンプルのため、応募前に公式サイトを確認してください。</div><div class="grid grid-2"><div class="card"><div class="analysis-block"><h3>あなたの就活軸</h3><p>${axis()}。${p.strengths||'経験と価値観'}を活かしながら、納得できる環境を探しています。</p></div><div class="analysis-block"><h3>強み</h3><p>${p.strengths||'プロフィールに強みを追加すると表示されます。'}</p></div><div class="analysis-block"><h3>向いている業界・職種</h3><div class="chip-list">${(p.industries||[]).concat(p.jobTypes||[]).map(x=>`<span class="chip">${x}</span>`).join('')||'<span class="chip">入力してください</span>'}</div></div></div><div class="card"><h3>データ管理</h3><p class="company-meta">プロフィール・選考・ES・面接メモを安全に持ち運べます。</p><div class="data-summary">${[['プロフィール',userCounts().profile?'作成済み':'未作成'],['保存企業',`${userCounts().saved}社`],['選考管理',`${userCounts().apps}件`],['ES下書き',`${userCounts().es}件`],['面接メモ',`${userCounts().answers}件`]].map(([a,b])=>`<div><small>${a}</small><strong>${b}</strong></div>`).join('')}</div><button class="secondary-btn" id="open-data-link">データ管理を開く</button></div></div>${aiSettingsHtml()}<div class="section-head"><div><h2>プロフィール完成度</h2><p>${p.updatedAt?`前回更新：${new Date(p.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'プロフィールを作成すると推薦精度が上がります'}</p></div></div><div class="card"><div class="metric-list">${[['基本情報',p.liberal&&p.grade?100:0],['希望条件',p.industries?.length&&p.jobTypes?.length?90:40],['経験・強み',p.strengths&&p.activities?90:35],['価値観',num(p.growth)+num(p.stability)>0?80:0]].map(([x,v])=>`<div class="metric"><span>${x}</span><div class="score-bar"><i style="width:${v}%;background:var(--green)"></i></div><b>${v}%</b></div>`).join('')}</div></div>`)}

/* Getting-started and data-management layer. */
const DATA_KEYS=['codra_profile','codra_saved_companies','codra_apps','codra_es_documents','codra_interview_answers','codra_company_research_notes'];
state.researchNotes=safeJSON('codra_company_research_notes',{});if(!state.researchNotes||typeof state.researchNotes!=='object'||Array.isArray(state.researchNotes))state.researchNotes={};
function userCounts(){return{profile:!!state.profile?.registered,saved:state.usingDemoSaved?0:state.saved.size,apps:state.usingDemoApps?0:state.apps.length,es:state.esDocs.length,answers:Object.values(state.interviewAnswers||{}).filter(x=>x&&String(x.answer||'').trim()).length}}
function readiness(){const x=userCounts();return[{label:'プロフィール作成済み',done:x.profile,action:'プロフィールを作成',view:'profile'},{label:'1社以上保存済み',done:x.saved>0,action:'企業を探す',view:'discover'},{label:'1件以上ES作成済み',done:x.es>0,action:'ESを作成',view:'documents'},{label:'1件以上面接メモ作成済み',done:x.answers>0,action:'面接メモを準備',view:'documents'},{label:'選考ステータス設定済み',done:state.apps.some(x=>x.status&&x.status!=='気になる'),action:'選考を管理',view:'saved'}]}
function dataBadge(type='sample'){return `<span class="data-badge ${type==='user'?'user-badge':'sample-badge'}">${type==='user'?'自分のデータ':'サンプル'}</span>`}
function readinessHtml(){const rows=readiness(),done=rows.filter(x=>x.done).length;return `<div class="card readiness-card"><div class="section-head" style="margin:0 0 12px"><div><h2>利用準備チェック</h2><p>${done}/${rows.length}項目完了</p></div><span class="tag ${done===rows.length?'tag-green':'tag-blue'}">${done===rows.length?'準備完了':'セットアップ中'}</span></div><div class="readiness-list">${rows.map(x=>`<div class="readiness-row ${x.done?'complete':''}"><span class="readiness-icon">${x.done?'✓':'○'}</span><span>${x.label}</span>${x.done?'<small>完了</small>':`<button class="link-btn" data-start-view="${x.view}">${x.action} →</button>`}</div>`).join('')}</div>${done===rows.length?'<p class="ready-message">Codraを使い始める準備ができています</p>':'<p class="setup-hint">上から順番に進めると、あなた向けの推薦と対策が充実します。</p>'}</div>`}
function emptyStart(){return `<div class="card first-start"><div class="eyebrow">Start here</div><h2>まずやること</h2><p>プロフィールから始めると、Codraがあなた向けの企業と対策を提案できます。</p><div class="start-actions"><button class="primary-btn" data-start-onboarding>① プロフィールを作成</button><button class="secondary-btn" data-start-view="discover">② 企業を探す</button><button class="secondary-btn" data-start-view="documents">③ ES下書きを作成</button><button class="secondary-btn" data-start-view="documents">④ 面接メモを準備</button></div></div>`}
function card(c){const s=c.scores||scores(c),r=c.rec||recommendation(c);return `<article class="card company-card"><div class="company-top"><div class="company-brand">${logo(c)}<div><div class="company-name">${c.name}</div><div class="company-meta">${c.category} · ${c.companySize}</div></div></div><div class="card-actions">${dataBadge('sample')}<label class="compare-check"><input type="checkbox" data-compare="${c.id}" ${state.compareIds.includes(c.id)?'checked':''}/> 比較</label><button class="save-btn ${state.saved.has(c.id)?'saved':''}" data-save="${c.id}" aria-label="${state.saved.has(c.id)?'保存を解除':'企業を保存'}">${state.saved.has(c.id)?'♥':'♡'}</button></div></div><div class="score-row"><div><div class="score">${s.total}<small> / 100</small></div><div class="company-meta">総合適合度</div></div><span class="tag ${s.total>=80?'tag-green':s.total>=60?'tag-blue':'tag-amber'}">${c.classification||classify(s.total)}</span></div><div class="score-bar"><i style="width:${s.total}%"></i></div><p class="reason">${r.main}</p><div class="recommend-details"><strong>共通点</strong><span>${r.matches.join(' / ')}</span><strong>注意点</strong><span>${r.cautions.join(' / ')}</span><strong>伸ばす要素</strong><span>${r.next.join(' / ')}</span></div><button class="link-btn detail-link" data-company="${c.id}">推薦理由と企業情報を見る →</button></article>`}
function getDataSnapshot(){return{version:1,exportedAt:new Date().toISOString(),codra_profile:state.profile,codra_saved_companies:[...state.saved],codra_apps:state.apps,codra_es_documents:state.esDocs,codra_interview_answers:state.interviewAnswers,codra_company_research_notes:state.researchNotes}}
function validateImport(x){if(!x||typeof x!=='object'||Array.isArray(x))throw Error('JSONの形式が正しくありません');if(x.codra_profile!==undefined&&(typeof x.codra_profile!=='object'||Array.isArray(x.codra_profile)))throw Error('プロフィールの形式が正しくありません');if(x.codra_saved_companies!==undefined&&(!Array.isArray(x.codra_saved_companies)||x.codra_saved_companies.some(id=>typeof id!=='string'||!company(id))))throw Error('保存企業の形式が正しくありません');if(x.codra_apps!==undefined&&(!Array.isArray(x.codra_apps)||x.codra_apps.some(a=>!a||typeof a!=='object'||!company(a.company))))throw Error('選考データの形式が正しくありません');if(x.codra_es_documents!==undefined&&(!Array.isArray(x.codra_es_documents)||x.codra_es_documents.some(d=>!d||typeof d!=='object'||!d.id||!company(d.companyId))))throw Error('ESデータの形式が正しくありません');if(x.codra_interview_answers!==undefined&&(typeof x.codra_interview_answers!=='object'||Array.isArray(x.codra_interview_answers)))throw Error('面接データの形式が正しくありません');if(x.codra_company_research_notes!==undefined&&(typeof x.codra_company_research_notes!=='object'||Array.isArray(x.codra_company_research_notes)))throw Error('企業研究メモの形式が正しくありません');return true}
function applySnapshot(x){if(x.codra_profile!==undefined)state.profile={...defaultProfile,...x.codra_profile};if(x.codra_saved_companies!==undefined){state.saved=new Set(x.codra_saved_companies);state.usingDemoSaved=false}if(x.codra_apps!==undefined){state.apps=x.codra_apps;state.usingDemoApps=false}if(x.codra_es_documents!==undefined)state.esDocs=x.codra_es_documents;if(x.codra_interview_answers!==undefined)state.interviewAnswers=x.codra_interview_answers;if(x.codra_company_research_notes!==undefined)state.researchNotes=x.codra_company_research_notes;persist();prepPersist();try{localStorage.setItem('codra_company_research_notes',JSON.stringify(state.researchNotes))}catch{}}
function confirmDataAction(title,body,action){const m=document.createElement('div');m.className='modal-backdrop';m.innerHTML=`<div class="modal confirm-modal" role="dialog" aria-modal="true"><button class="modal-close" aria-label="閉じる">×</button><div class="eyebrow">Data safety</div><h2>${title}</h2><p class="modal-desc">${body}</p><div class="modal-actions"><button class="secondary-btn" data-confirm-cancel>キャンセル</button><button class="primary-btn danger-btn" data-confirm-ok>実行する</button></div></div>`;document.body.appendChild(m);const close=()=>m.remove();m.querySelector('.modal-close').onclick=close;m.querySelector('[data-confirm-cancel]').onclick=close;m.querySelector('[data-confirm-ok]').onclick=()=>{action();close()}}
function dataManager(){const x=userCounts();const m=document.createElement('div');m.className='modal-backdrop';m.innerHTML=`<div class="modal data-modal" role="dialog" aria-modal="true" aria-labelledby="data-title"><button class="modal-close" id="data-close" aria-label="閉じる">×</button><div class="eyebrow">Data management</div><h2 id="data-title">データ管理</h2><p class="modal-desc">Codraの入力データを確認・保存・移行できます。</p><div class="data-summary">${[['プロフィール',x.profile?'作成済み':'未作成'],['保存企業',`${x.saved}社`],['選考管理',`${x.apps}件`],['ES下書き',`${x.es}件`],['面接メモ',`${x.answers}件`]].map(([a,b])=>`<div><small>${a}</small><strong>${b}</strong></div>`).join('')}</div><div class="data-actions"><button class="secondary-btn" id="export-json">JSONをダウンロード</button><button class="secondary-btn" id="copy-json">JSONをコピー</button><button class="secondary-btn" id="import-json">JSONを読み込む</button></div><textarea class="textarea data-textarea" id="data-json" rows="8" placeholder="エクスポートしたJSONを貼り付けてください"></textarea><p class="data-note">読み込み前に形式を検証します。エラーがある場合、既存データは変更しません。</p><div class="data-danger"><button class="secondary-btn" id="reset-user">ユーザーデータをリセット</button><button class="secondary-btn danger-btn" id="reset-all">全データをリセット</button></div></div>`;document.body.appendChild(m);const close=()=>m.remove();m.querySelector('#data-close').onclick=close;m.querySelector('#export-json').onclick=()=>{const text=JSON.stringify(getDataSnapshot(),null,2);m.querySelector('#data-json').value=text;const blob=new Blob([text],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`codra-data-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(a.href);toast('データを書き出しました')};m.querySelector('#copy-json').onclick=async()=>{const text=JSON.stringify(getDataSnapshot(),null,2);m.querySelector('#data-json').value=text;try{await navigator.clipboard.writeText(text);toast('JSONをコピーしました')}catch{toast('コピーできませんでした。テキストを選択してコピーしてください')}};m.querySelector('#import-json').onclick=()=>{try{const x=JSON.parse(m.querySelector('#data-json').value);validateImport(x);applySnapshot(x);close();toast('データを読み込みました');render()}catch(e){toast(`読み込みエラー：${e.message}`)}};m.querySelector('#reset-user').onclick=()=>confirmDataAction('ユーザーデータをリセットしますか？','プロフィール、保存企業、選考、ES、面接メモを削除します。サンプル企業情報は残ります。',()=>{state.profile={...defaultProfile};state.saved=new Set();state.apps=[];state.esDocs=[];state.interviewAnswers={};state.researchNotes={};DATA_KEYS.forEach(k=>{try{localStorage.removeItem(k)}catch{}});close();toast('ユーザーデータをリセットしました');render()});m.querySelector('#reset-all').onclick=()=>confirmDataAction('全データをリセットしますか？','Codraに保存された対象データをすべて削除します。この操作は取り消せません。',()=>{DATA_KEYS.forEach(k=>{try{localStorage.removeItem(k)}catch{}});state.profile={...defaultProfile};state.saved=new Set();state.apps=[];state.esDocs=[];state.interviewAnswers={};state.researchNotes={};close();toast('全データをリセットしました');render()})}

function dashboard(){const list=ranked(),pc=completion(),first=!state.profile.registered;layout(`<section class="hero"><div><div class="eyebrow">Your career strategy</div><h1>${first?'Codraを始めましょう。':'こんにちは、ゆうきさん。'}</h1><p>${first?'プロフィールを登録すると、あなた向けの企業と準備方法を提案できます。':'今日も、自分らしいキャリアを一歩ずつ設計しましょう。'}</p></div><div class="hero-side"><div><div class="stat-label">プロフィール完成度</div><div class="stat-value">${pc}<small>%</small></div></div><div class="progress-ring" style="background:conic-gradient(var(--green) ${pc}%,#e8edf3 0)"><span>${pc}%</span></div></div></section>${first?emptyStart():''}${readinessHtml()}<div class="notice source-notice">企業情報・選考情報はサンプルです。応募や面接準備の前に、必ず企業公式サイトで最新情報を確認してください。</div><div class="grid grid-4"><div class="card stat-card"><div class="stat-label">就活進捗率</div><div class="stat-value">38<small>%</small></div><div class="stat-foot">↑ 先週より 8%</div></div><div class="card stat-card"><div class="stat-label">保存した企業</div><div class="stat-value">${state.saved.size}<small> 社</small></div><div class="stat-foot">${state.saved.size?'自分のデータ':'まず企業を保存しましょう'}</div></div><div class="card stat-card"><div class="stat-label">選考中の企業</div><div class="stat-value">${state.apps.length}<small> 社</small></div><div class="stat-foot">${state.apps.length?'次のアクションがあります':'応募後に登録できます'}</div></div><div class="card stat-card"><div class="stat-label">ES・面接対策</div><div class="stat-value">${state.esDocs.length+userCounts().answers}<small> 件</small></div><div class="stat-foot">自分のデータ</div></div></div><div class="grid grid-2"><div><div class="section-head"><div><h2>今日やるべきこと</h2><p>締切・志望度・準備状況から優先度を算出</p></div><button class="link-btn" data-view="saved">すべて見る</button></div><div class="card">${state.apps.length?state.apps.map((a,i)=>{const c=company(a.company);return c?`<div class="task ${state.doneTasks.has(i)?'done':''}"><button class="task-check" data-task="${i}">${state.doneTasks.has(i)?'✓':''}</button><div><div class="task-title">${a.next}</div><div class="task-sub">${c.name} · 締切 ${a.deadline.slice(5).replace('-','/')}</div></div><span class="task-priority">優先度 ${a.priority}</span></div>`:''}).join(''):`<div class="empty compact-empty"><strong>まだタスクがありません</strong>企業を保存して選考状況を登録すると表示されます。</div>`}</div></div><div><div class="section-head"><div><h2>締切が近い企業</h2><p>忘れないうちに次の一手を</p></div><button class="link-btn" data-view="saved">選考管理</button></div><div class="card">${state.apps.length?state.apps.map(a=>{const c=company(a.company);return c?`<div class="deadline"><div><div class="deadline-title">${c.name}</div><div class="deadline-company">${a.status} ${dataBadge('user')}</div></div><div class="date ${a.priority==='高'?'':'normal'}">${a.deadline.slice(5).replace('-','/')}<small> 締切</small></div></div>`:''}).join(''):`<div class="empty compact-empty"><strong>締切はまだありません</strong>選考管理から締切を登録できます。</div>`}</div></div></div><div class="section-head"><div><h2>あなた向けおすすめ企業</h2><p>${first?'プロフィール作成後にあなた向けへ更新されます':'プロフィールと重視度から再計算した現時点の仮説'}</p></div><div class="section-actions"><button class="secondary-btn" id="recalculate">↻ 再計算する</button><button class="link-btn" data-view="discover">企業を探す →</button></div></div><div class="grid grid-3">${list.slice(0,3).map(card).join('')}</div></div>`)}
function profile(){const p=state.profile;layout(`<div class="eyebrow">Profile intelligence</div><h1 class="page-title">プロフィール分析</h1><p class="page-desc">入力した情報から見えた、現時点でのキャリア仮説です。</p><div class="section-actions profile-actions"><button class="primary-btn" id="edit-profile">プロフィールを編集</button><button class="secondary-btn" id="profile-reset">入力をリセット</button><button class="secondary-btn" id="open-data">データ管理</button></div><div class="notice">これはAIによる断定ではなく、入力情報から導いた現時点の仮説です。企業情報はサンプルのため、応募前に公式サイトを確認してください。</div><div class="grid grid-2"><div class="card"><div class="analysis-block"><h3>あなたの就活軸</h3><p>${axis()}。${p.strengths||'経験と価値観'}を活かしながら、納得できる環境を探しています。</p></div><div class="analysis-block"><h3>強み</h3><p>${p.strengths||'プロフィールに強みを追加すると表示されます。'}</p></div><div class="analysis-block"><h3>適性のある働き方</h3><p>${p.remote>=65?'リモートワークを取り入れ、集中と対話を組み合わせる働き方。':'対面での協働を軸に、必要に応じてリモートを組み合わせる働き方。'}</p></div></div><div class="card"><div class="analysis-block"><h3>向いている業界</h3><div class="chip-list">${(p.industries||[]).map(x=>`<span class="chip">${x}</span>`).join('')||'<span class="chip">入力してください</span>'}</div></div><div class="analysis-block"><h3>向いている職種</h3><div class="chip-list">${(p.jobTypes||[]).map(x=>`<span class="chip">${x}</span>`).join('')||'<span class="chip">入力してください</span>'}</div></div></div></div><div class="section-head"><div><h2>データ管理</h2><p>プロフィール・選考・ES・面接メモを安全に持ち運べます</p></div><button class="link-btn" id="open-data-link">管理画面を開く →</button></div><div class="card data-summary-card"><div class="data-summary">${[['プロフィール',userCounts().profile?'作成済み':'未作成'],['保存企業',`${userCounts().saved}社`],['選考管理',`${userCounts().apps}件`],['ES下書き',`${userCounts().es}件`],['面接メモ',`${userCounts().answers}件`]].map(([a,b])=>`<div><small>${a}</small><strong>${b}</strong></div>`).join('')}</div></div><div class="section-head"><div><h2>プロフィール完成度</h2><p>${p.updatedAt?`前回更新：${new Date(p.updatedAt).toLocaleString('ja-JP',{dateStyle:'medium',timeStyle:'short'})}`:'プロフィールを作成すると推薦精度が上がります'}</p></div></div><div class="card"><div class="metric-list">${[['基本情報',p.liberal&&p.grade?100:0],['希望条件',p.industries?.length&&p.jobTypes?.length?90:40],['経験・強み',p.strengths&&p.activities?90:35],['価値観',num(p.growth)+num(p.stability)>0?80:0]].map(([x,v])=>`<div class="metric"><span>${x}</span><div class="score-bar"><i style="width:${v}%;background:var(--green)"></i></div><b>${v}%</b></div>`).join('')}</div></div>`)}

function bind(){document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{state.view=b.dataset.view;state.companyId=null;render()});document.querySelectorAll('[data-start-view]').forEach(b=>b.onclick=()=>{state.view=b.dataset.startView;render()});document.querySelectorAll('[data-start-onboarding]').forEach(b=>b.onclick=()=>profileModal(true));document.querySelectorAll('[data-save]').forEach(b=>b.onclick=()=>{const id=b.dataset.save;state.usingDemoSaved=false;state.saved.has(id)?state.saved.delete(id):state.saved.add(id);persist();toast(state.saved.has(id)?'自分のデータに保存しました':'保存を解除しました');render()});document.querySelectorAll('.detail-link').forEach(b=>b.onclick=()=>{state.companyId=b.dataset.company;state.view='detail';state.tab='overview';render()});document.querySelectorAll('[data-filter]').forEach(b=>b.onclick=()=>{state.filter=b.dataset.filter;render()});document.querySelector('#search-btn')?.addEventListener('click',()=>{state.query=document.querySelector('#company-search').value;render()});document.querySelector('#company-search')?.addEventListener('keydown',e=>{if(e.key==='Enter'){state.query=e.target.value;render()}});document.querySelectorAll('[data-task]').forEach(b=>b.onclick=()=>{state.doneTasks.has(+b.dataset.task)?state.doneTasks.delete(+b.dataset.task):state.doneTasks.add(+b.dataset.task);render()});document.querySelectorAll('[data-status]').forEach(s=>s.onchange=()=>{state.usingDemoApps=false;state.apps[+s.dataset.status].status=s.value;persist();toast('選考状況を更新しました')});document.querySelectorAll('[data-tab]').forEach(b=>b.onclick=()=>{state.tab=b.dataset.tab;render()});document.querySelectorAll('[data-compare]').forEach(x=>x.onchange=()=>{if(x.checked){if(state.compareIds.length>=3){x.checked=false;toast('比較できるのは最大3社です');return}state.compareIds.push(x.dataset.compare)}else state.compareIds=state.compareIds.filter(id=>id!==x.dataset.compare);render()});document.querySelector('#compare-btn')?.addEventListener('click',()=>{state.view='compare';render()});document.querySelector('#recalculate')?.addEventListener('click',()=>{toast('プロフィールをもとに推薦を再計算しました');render()});document.querySelector('#edit-profile')?.addEventListener('click',()=>profileModal(false));document.querySelector('#profile-reset')?.addEventListener('click',()=>confirmDataAction('プロフィールをリセットしますか？','入力したプロフィールだけを初期状態に戻します。保存企業やESは残ります。',()=>{state.profile={...defaultProfile};persist();toast('プロフィールをリセットしました');render()}));document.querySelector('#open-data')?.addEventListener('click',dataManager);document.querySelector('#open-data-link')?.addEventListener('click',dataManager);document.querySelector('#new-es')?.addEventListener('click',esCreateModal);document.querySelectorAll('[data-new-es-company]').forEach(b=>b.onclick=()=>{const d=newDoc(b.dataset.newEsCompany,'志望動機');state.esDocs.unshift(d);prepPersist();editEs(d.id)});document.querySelectorAll('[data-edit-es]').forEach(b=>b.onclick=()=>editEs(b.dataset.editEs));document.querySelectorAll('[data-interview-company]').forEach(b=>b.onclick=()=>interviewPrep(b.dataset.interviewCompany));document.querySelector('.mobile-menu')?.addEventListener('click',()=>document.querySelector('.sidebar').classList.toggle('open'))}
render();
